import React, { useState } from "react";
import {
  theme, Typography, Space, Button, Progress, Input, Slider, Divider, Popover, Select
} from "antd";
import {
  LeftOutlined, RightOutlined, DoubleLeftOutlined, DoubleRightOutlined,
  UnorderedListOutlined
} from "@ant-design/icons";
import { useLabelingStore } from "../store/useLabelingStore";
import { useTranslation } from "react-i18next";

const { Text } = Typography;
const { TextArea } = Input;
const defectReasonValues = [ "wrong_class", "loose_tightness", "missed_point", "missed_object", "duplicate", "other" ];

export default function LabelingImagePanel() {
  const { token } = theme.useToken();
  const { t } = useTranslation(["labeling", "common"]);
  const {
    currentImageIndex, setCurrentImageIndex, filters, setFilter, defectStatus,
    activeStatus, toggleDefectStatus, toggleWorkStatus, labelingDefectStatus,
    toggleLabelingDefectStatus, labelingDefectReason, setLabelingDefectReason,
    imageDescription, setImageDescription
  } = useLabelingStore();
  
  const currentNum = currentImageIndex + 1;
  const totalNum = 24; 
  const progressPercent = Math.round((currentNum / totalNum) * 1000) / 10;

  const isDefect = defectStatus === "defect";
  const isLabelingDefect = labelingDefectStatus === "defect";
  const isDone = activeStatus === "done";
  const accentColor = isDone ? token.colorWarning : token.colorTextSecondary;

  return (
    <div style={{ padding: "8px 24px 12px 24px", background: token.colorBgElevated, color: token.colorText, borderTop: `1px solid ${token.colorBorderSecondary}`, height: "90px", display: "flex", alignItems: "stretch", gap: 32 }}>
      <div style={{ display: "flex", flexDirection: "column", gap: 8, minWidth: 460 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <Space size={4}>
            <NavBtn icon={<DoubleLeftOutlined />} onClick={() => setCurrentImageIndex(0)} />
            <NavBtn icon={<LeftOutlined />} onClick={() => setCurrentImageIndex(Math.max(0, currentImageIndex - 1))} />
          </Space>
          <div style={{ flex: 1, position: "relative", display: "flex", flexDirection: "column", alignItems: "center" }}>
            <div style={{ width: "100%", height: 32, border: `1px solid ${accentColor}`, borderRadius: 16, display: "flex", alignItems: "center", padding: "0 16px", background: token.colorFillQuaternary }}>
              <Text style={{ color: token.colorText, fontSize: 12, fontFamily: "monospace", letterSpacing: "-0.5px" }}>S63_DATA1_W1_L1_D2023-06-01-14-23_001_00000{currentNum}.jpg</Text>
            </div>
          </div>
          <Space size={4}>
            <NavBtn icon={<RightOutlined />} onClick={() => setCurrentImageIndex(Math.min(totalNum - 1, currentImageIndex + 1))} />
            <NavBtn icon={<DoubleRightOutlined />} onClick={() => setCurrentImageIndex(totalNum - 1)} />
          </Space>
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <Progress percent={progressPercent} showInfo={false} strokeColor={token.colorSuccess} railColor={token.colorFillSecondary} size={[-1, 6]} style={{ margin: 0 }} />
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <Text style={{ color: token.colorTextDescription, fontSize: 13, fontWeight: "bold" }}>{progressPercent.toFixed(1)}%</Text>
            <Text style={{ color: token.colorTextDescription, fontSize: 12 }}>({t("panel.current")}: {currentNum} / {t("panel.total")}: {totalNum})</Text>
          </div>
        </div>
      </div>

      <Divider orientation="vertical" style={{ height: "100%", borderColor: token.colorBorderSecondary, margin: 0 }} />

      <div style={{ display: "flex", alignItems: "flex-start", paddingLeft: 24, paddingTop: 4 }}>
        <div style={{ display: "flex", gap: 32, alignItems: "center" }}>
          <CompactItem label={t("panel.workStatus")} control={
              <div onClick={toggleWorkStatus} style={{ background: isDone ? token.colorSuccessBg : token.colorFillQuaternary, padding: "2px 10px", borderRadius: 4, display: "flex", alignItems: "center", gap: 8, border: `1px solid ${isDone ? token.colorSuccess : token.colorBorderSecondary}`, minWidth: 80, justifyContent: "center", cursor: "pointer" }}>
                <div style={{ width: 6, height: 6, background: isDone ? token.colorSuccess : token.colorText, borderRadius: "50%" }} />
                <Text style={{ color: isDone ? token.colorSuccess : token.colorTextSecondary, fontSize: 11, fontWeight: "bold" }}>{isDone ? t("panel.done") : t("panel.working")}</Text>
              </div>
          } />
          <Divider orientation="vertical" style={{ height: 32, borderColor: token.colorBorderSecondary, margin: 0 }} />
          <div style={{ display: "flex", gap: 24 }}>
            <CompactItem label={t("panel.imageDefect")} control={
                <div onClick={toggleDefectStatus} style={{ background: !isDefect ? token.colorSuccessBg : token.colorErrorBg, padding: "2px 10px", borderRadius: 4, display: "flex", alignItems: "center", gap: 8, border: `1px solid ${isDefect ? token.colorError : token.colorSuccess}`, minWidth: 70, justifyContent: "center", cursor: "pointer" }}>
                  <div style={{ width: 6, height: 6, background: isDefect ? token.colorError : token.colorSuccess, borderRadius: "50%" }} />
                  <Text style={{ color: isDefect ? token.colorError : token.colorSuccess, fontSize: 11, fontWeight: "bold" }}>{isDefect ? t("panel.defect") : t("panel.normal")}</Text>
                </div>
            } />
            <CompactItem label={t("panel.labelDefect")} control={
                <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                  <div onClick={toggleLabelingDefectStatus} style={{ background: !isLabelingDefect ? token.colorSuccessBg : token.colorErrorBg, padding: "2px 10px", borderRadius: 4, display: "flex", alignItems: "center", gap: 8, border: `1px solid ${isLabelingDefect ? token.colorError : token.colorSuccess}`, minWidth: 70, justifyContent: "center", cursor: "pointer" }}>
                    <div style={{ width: 6, height: 6, background: isLabelingDefect ? token.colorError : token.colorSuccess, borderRadius: "50%" }} />
                    <Text style={{ color: isLabelingDefect ? token.colorError : token.colorSuccess, fontSize: 11, fontWeight: "bold" }}>{isLabelingDefect ? t("panel.defect") : t("panel.normal")}</Text>
                  </div>
                  {isLabelingDefect && <DefectReasonPopover value={labelingDefectReason} onChange={setLabelingDefectReason} t={t} />}
                </div>
            } />
          </div>
        </div>
      </div>

      <div style={{ display: "flex", alignItems: "stretch", gap: 24, flex: 1 }}>
        <Divider orientation="vertical" style={{ height: "100%", borderColor: token.colorBorderSecondary, margin: 0 }} />
        <div style={{ display: "flex", flexDirection: "column", gap: 12, paddingTop: 4 }}>
          <div style={{ display: "flex", gap: 16 }}>
            <CompactItem label={t("panel.imageSize")} control={<div style={{ background: token.colorFillQuaternary, padding: "2px 12px", borderRadius: 4, display: "flex", alignItems: "baseline", gap: 4, border: `1px solid ${token.colorBorderSecondary}`, minWidth: 100, justifyContent: "center" }}><Text style={{ color: token.colorText, fontSize: 12, fontWeight: "800" }}>1920 × 1080</Text></div>} />
            <CompactItem label={t("panel.fileSize")} control={<div style={{ background: token.colorFillQuaternary, padding: "2px 12px", borderRadius: 4, display: "flex", alignItems: "baseline", gap: 4, border: `1px solid ${token.colorBorderSecondary}`, minWidth: 80, justifyContent: "center" }}><Text style={{ color: token.colorText, fontSize: 12, fontWeight: "800" }}>660.6</Text><Text style={{ color: token.colorTextDescription, fontSize: 9 }}>KB</Text></div>} />
          </div>
        </div>
        <div style={{ flex: 1, display: "flex", alignItems: "flex-start", gap: 16, paddingTop: 4 }}>
          <Text style={{ color: token.colorTextDescription, fontSize: 10, fontWeight: "bold", textTransform: "uppercase", letterSpacing: "0.5px", whiteSpace: "nowrap", lineHeight: "15px" }}>{t("panel.imgDesc")}</Text>
          <TextArea 
            placeholder={t("panel.imgDescPlaceholder")} 
            autoSize={{ minRows: 2, maxRows: 2 }} 
            style={{ flex: 1, background: token.colorFillQuaternary, border: `1px solid ${token.colorBorderSecondary}`, color: token.colorText, fontSize: 12, borderRadius: 6, resize: "none", padding: "4px 8px" }}
            value={imageDescription}
            onChange={(e) => setImageDescription(e.target.value)}
          />
        </div>
      </div>
    </div>
  );
}

function NavBtn({ icon, onClick }: { icon: React.ReactNode; onClick: () => void; }) {
  const { token } = theme.useToken();
  return <Button type="text" size="small" icon={icon} style={{ background: token.colorFillSecondary, width: 32, height: 32, borderRadius: 4, display: "flex", alignItems: "center", justifyContent: "center", color: token.colorTextDescription }} onClick={onClick} />;
}

function CompactItem({ label, control }: { label: string; control: React.ReactNode; }) {
  const { token } = theme.useToken();
  return <div style={{ display: "flex", flexDirection: "column", gap: 4 }}><Text style={{ color: token.colorTextDescription, fontSize: 10, fontWeight: "bold", textTransform: "uppercase", letterSpacing: "0.5px", whiteSpace: "nowrap" }}>{label}</Text>{control}</div>;
}

function DefectReasonPopover({ value, onChange, t }: { value: string | null; onChange: (v: string | null) => void; t: any; }) {
  const { token } = theme.useToken();
  const selectedLabel = value ? t(`panel.reasons.${value}`) : t("panel.reasonSelectBtn");

  return (
    <Popover trigger="click" placement="top" color={token.colorBgElevated} title={<Text style={{ color: token.colorTextDescription, fontSize: 11 }}>{t("panel.reasonSelectBtn")}</Text>} content={
        <div style={{ display: "flex", flexDirection: "column", gap: 4, padding: "8px 0", minWidth: 160 }}>
          {defectReasonValues.map((r) => (
            <div key={r} onClick={() => onChange(r)} style={{ padding: "8px 12px", cursor: "pointer", borderRadius: 4, background: value === r ? token.colorPrimaryBg : "transparent", color: value === r ? token.colorPrimary : token.colorText, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <Text style={{ fontSize: 12, color: "inherit" }}>{t(`panel.reasons.${r}`)}</Text>
              {value === r && <div style={{ width: 6, height: 6, borderRadius: "50%", background: token.colorPrimary }} />}
            </div>
          ))}
          {value && <div onClick={() => onChange(null)} style={{ borderTop: `1px solid ${token.colorBorderSecondary}`, marginTop: 4, paddingTop: 8, paddingLeft: 12, cursor: "pointer" }}><Text style={{ fontSize: 11, color: token.colorError }}>{t("common.reset")}</Text></div>}
        </div>
      }
    >
      <div style={{ cursor: "pointer", display: "flex", alignItems: "center", gap: 10, background: token.colorFillQuaternary, padding: "2px 14px", borderRadius: 6, border: `1px solid ${token.colorBorderSecondary}`, minWidth: 160 }}>
        <UnorderedListOutlined style={{ fontSize: 13, color: value ? token.colorPrimary : token.colorTextDescription }} />
        <Text style={{ color: value ? token.colorText : token.colorTextDescription, fontSize: 12, fontWeight: value ? "bold" : "normal" }}>{selectedLabel}</Text>
      </div>
    </Popover>
  );
}
