import React, { useState } from "react";
import {
  theme,
  Typography,
  Space,
  Button,
  Tag,
  Select,
  Collapse,
  Input,
  InputNumber,
  App,
  Tooltip,
} from "antd";
import {
  EyeOutlined,
  EyeInvisibleOutlined,
  LockOutlined,
  UnlockOutlined,
  DeleteOutlined,
  RadiusSettingOutlined,
  DeploymentUnitOutlined,
  DotChartOutlined,
  DownOutlined,
  UpOutlined,
  FontSizeOutlined,
  GroupOutlined,
  WarningFilled,
} from "@ant-design/icons";
import {
  useLabelingStore,
  LabelShape,
  KeypointPart,
} from "../store/useLabelingStore";
import { useTranslation } from "react-i18next";

const { Text } = Typography;

// Custom BBox Icon (Shared with Toolbar)
const BboxIcon = () => (
  <svg
    width="12"
    height="12"
    viewBox="0 0 24 24"
    fill="none"
    stroke="currentColor"
    strokeWidth="2.5"
    strokeLinecap="round"
    strokeLinejoin="round"
  >
    <rect x="3" y="3" width="18" height="18" />
    <circle cx="3" cy="3" r="2.5" fill="currentColor" stroke="none" />
    <circle cx="21" cy="3" r="2.5" fill="currentColor" stroke="none" />
    <circle cx="3" cy="21" r="2.5" fill="currentColor" stroke="none" />
    <circle cx="21" cy="21" r="2.5" fill="currentColor" stroke="none" />
  </svg>
);

const isOutOfBounds = (shape: LabelShape, imgW: number, imgH: number) => {
  if (imgW === 0 || imgH === 0) return false;
  if (shape.type === "rect") {
    const x = shape.x ?? 0;
    const y = shape.y ?? 0;
    return (
      x < 0 ||
      y < 0 ||
      x + (shape.width || 0) > imgW ||
      y + (shape.height || 0) > imgH
    );
  }
  return (
    shape.points?.some((v, i) =>
      i % 2 === 0 ? v < 0 || v > imgW : v < 0 || v > imgH,
    ) || false
  );
};

export default function LabelingObjectList() {
  const { token } = theme.useToken();
  const { t } = useTranslation(["labeling", "common"]);
  const { shapes, selectedShapeIds, classes, imageWidth, imageHeight } =
    useLabelingStore();

  const rectCount = shapes.filter((s) => s.type === "rect").length;
  const polyCount = shapes.filter((s) => s.type === "polygon").length;
  const kpCount = shapes.filter((s) => s.type === "keypoint").length;

  return (
    <div
      style={{
        padding: "0",
        height: "100%",
        overflowY: "auto",
        background: token.colorBgContainer,
        borderLeft: `1px solid ${token.colorBorderSecondary}`,
      }}
    >
      {/* 1. Summary Section */}
      <div style={{ background: token.colorBgElevated, paddingBottom: 12 }}>
        <div
          style={{
            padding: "10px 12px",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <Text
            style={{ color: token.colorText, fontSize: 11, fontWeight: "bold" }}
          >
            {t("panel.objectList.summary")}
          </Text>
          <UpOutlined
            style={{ fontSize: 10, color: token.colorTextDescription }}
          />
        </div>
        <div
          style={{
            padding: "0 12px",
            display: "flex",
            justifyContent: "space-between",
            gap: 8,
          }}
        >
          <SummaryBox icon={<BboxIcon />} count={rectCount} />
          <SummaryBox icon={<DeploymentUnitOutlined />} count={polyCount} />
          <SummaryBox icon={<DotChartOutlined />} count={kpCount} />
        </div>
      </div>
      <div
        style={{
          height: 1,
          background: token.colorBorderSecondary,
          margin: "0 12px",
        }}
      />
      {/* 2. List Section */}
      <div>
        <div
          style={{
            padding: "10px 12px",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <Text
            style={{ color: token.colorText, fontSize: 11, fontWeight: "bold" }}
          >
            {t("panel.objectList.title")}
          </Text>
          <UpOutlined
            style={{ fontSize: 10, color: token.colorTextDescription }}
          />
        </div>
        <div style={{ padding: "0 10px" }}>
          {shapes.length === 0 ? (
            <div
              style={{
                padding: "40px 0",
                textAlign: "center",
                color: token.colorTextDescription,
                fontSize: 11,
              }}
            >
              {t("noObjects", { ns: "common" })}
            </div>
          ) : (
            shapes.map((shape, idx) => (
              <ObjectGroup
                key={shape.id}
                shape={shape}
                index={idx}
                isSelected={selectedShapeIds.includes(shape.id)}
                classes={classes}
                imgW={imageWidth}
                imgH={imageHeight}
              />
            ))
          )}
        </div>
      </div>
    </div>
  );
}

function SummaryBox({ icon, count }: { icon: React.ReactNode; count: number }) {
  const { token } = theme.useToken();
  return (
    <div
      style={{
        flex: 1,
        background: token.colorFillQuaternary,
        borderRadius: 4,
        padding: "8px 4px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        gap: 12,
        border: `1px solid ${token.colorBorderSecondary}`,
      }}
    >
      <div style={{ color: token.colorTextDescription, fontSize: 14 }}>
        {icon}
      </div>
      <Text
        style={{ color: token.colorText, fontSize: 14, fontWeight: "bold" }}
      >
        {count}
      </Text>
    </div>
  );
}

function ObjectGroup({
  shape,
  index,
  isSelected,
  classes,
  imgW,
  imgH,
}: {
  shape: LabelShape;
  index: number;
  isSelected: boolean;
  classes: any[];
  imgW: number;
  imgH: number;
}) {
  const { token } = theme.useToken();
  const {
    selectShape,
    toggleLock,
    toggleVisibility,
    toggleObjectLabel,
    updateShape,
    updateKeypointPart,
    selectKeypointPart,
  } = useLabelingStore();
  const { t } = useTranslation(["labeling", "common"]);
  const [isExpanded, setIsExpanded] = useState(true);
  
  const getIcon = () => {
    if (shape.type === "rect") return <BboxIcon />;
    if (shape.type === "keypoint") return <DotChartOutlined />;
    return <DeploymentUnitOutlined />;
  };
  
  const handleClassChange = (val: string) => {
    const cls = classes.find((c) => c.id === val);
    if (cls)
      updateShape(shape.id, {
        classId: cls.id,
        className: cls.name,
        color: cls.color,
      });
  };

  const outOfBounds = isOutOfBounds(shape, imgW, imgH);

  return (
    <div
      style={{
        background: isSelected ? token.colorPrimaryBg : token.colorBgElevated,
        borderRadius: 4,
        marginBottom: 8,
        overflow: "hidden",
        border: "1px solid",
        borderColor: isSelected ? token.colorPrimaryBorder : "transparent",
        display: "flex",
        opacity: shape.locked ? 0.6 : 1,
      }}
      onClick={(e) => {
        e.stopPropagation();
        selectShape(shape.id, e.ctrlKey || e.altKey);
      }}
    >
      <div
        style={{
          width: 3,
          background: isSelected ? shape.color || "#1890ff" : "transparent",
        }}
      />
      <div style={{ flex: 1 }}>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            padding: "8px 10px",
            justifyContent: "space-between",
          }}
        >
          <Space size={8}>
            <Tooltip title={
              shape.type === 'rect' ? t('toolbar.bbox') :
              shape.type === 'polygon' ? t('toolbar.polygon') :
              shape.type === 'keypoint' ? t('toolbar.keypoint') :
              shape.type
            } placement="left">
              <span
                style={{
                  color: shape.locked
                    ? token.colorTextQuaternary
                    : token.colorTextSecondary,
                  fontSize: 14,
                  cursor: "help",
                }}
              >
                {getIcon()}
              </span>
            </Tooltip>
            {outOfBounds && (
              <Tooltip title={t("panel.objectList.outOfBounds")} placement="top">
                <WarningFilled style={{ color: "#faad14", fontSize: 13 }} />
              </Tooltip>
            )}
          </Space>
          <Space size={0}>
            <Select
              size="small"
              value={shape.classId}
              style={{ width: 110 }}
              variant="borderless"
              onChange={(v) => {
                handleClassChange(v);
              }}
              onClick={(e) => e.stopPropagation()}
              classNames={{ popup: { root: "object-class-dropdown" } }}
              className="object-class-select"
            >
              {classes.map((c, i) => (
                <Select.Option key={c.id} value={c.id}>
                  {i}: {c.name}
                </Select.Option>
              ))}
            </Select>
            <Button
              size="small"
              type="text"
              icon={
                isExpanded ? (
                  <DownOutlined style={{ fontSize: 10 }} />
                ) : (
                  <DownOutlined
                    style={{ fontSize: 10, transform: "rotate(-90deg)" }}
                  />
                )
              }
              onClick={(e) => {
                e.stopPropagation();
                setIsExpanded(!isExpanded);
              }}
              style={{ color: token.colorTextDescription }}
            />
          </Space>
        </div>
        {isExpanded && (
          <div style={{ padding: "0 10px 10px 10px" }}>
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: 6,
                marginBottom: 8,
              }}
            >
              <div
                style={{
                  background: isSelected
                    ? token.colorFillSecondary
                    : token.colorFillQuaternary,
                  borderRadius: 4,
                  height: 24,
                  padding: "0 8px",
                  display: "flex",
                  alignItems: "center",
                  border: `1px solid ${token.colorBorderSecondary}`,
                }}
              >
                <Text style={{ color: token.colorText, fontSize: 11 }}>
                  {t("panel.objectList.class")}
                </Text>
                <Text
                  style={{
                    color: shape.color || token.colorText,
                    fontSize: 11,
                    fontWeight: "bold",
                    marginLeft: 8,
                  }}
                >
                  {shape.classId || "0"}
                </Text>
              </div>
              <div
                style={{
                  flex: 1,
                  background: token.colorFillQuaternary,
                  borderRadius: 4,
                  height: 24,
                  padding: "0 8px",
                  display: "flex",
                  alignItems: "center",
                  gap: 8,
                  border: `1px solid ${token.colorBorderSecondary}`,
                }}
              >
                <Text
                  style={{ color: token.colorTextDescription, fontSize: 11 }}
                >
                  {t("panel.objectList.id")}
                </Text>
                <Text style={{ color: token.colorTextSecondary, fontSize: 11 }}>
                  {index + 1}
                </Text>
              </div>
              {shape.groupId && (
                <Tooltip title={`Group: ${shape.groupId}`}>
                  <div
                    style={{
                      background: "rgba(82,196,26,0.1)",
                      border: "1px solid rgba(82,196,26,0.2)",
                      borderRadius: 4,
                      height: 24,
                      padding: "0 8px",
                      display: "flex",
                      alignItems: "center",
                      gap: 4,
                    }}
                  >
                    <GroupOutlined style={{ color: "#52c41a", fontSize: 10 }} />
                    <Text
                      style={{
                        color: "#52c41a",
                        fontSize: 9,
                        fontWeight: "bold",
                      }}
                    >
                      {t("panel.objectList.group")}
                    </Text>
                  </div>
                </Tooltip>
              )}
              <Space size={2}>
                <IconButton
                  active={shape.visible}
                  icon={
                    shape.visible ? <EyeOutlined /> : <EyeInvisibleOutlined />
                  }
                  onClick={() => toggleVisibility(shape.id)}
                />
                <IconButton
                  active={shape.showName}
                  icon={<FontSizeOutlined />}
                  onClick={() => toggleObjectLabel(shape.id)}
                />
                <IconButton
                  active={shape.locked}
                  icon={shape.locked ? <LockOutlined /> : <UnlockOutlined />}
                  onClick={() => toggleLock(shape.id)}
                />
              </Space>
            </div>
            {shape.type === "keypoint" && shape.keypointParts && (
              <div style={{ marginTop: 8 }}>
                <Text
                  style={{
                    color: token.colorTextDescription,
                    fontSize: 11,
                    marginBottom: 8,
                    display: "block",
                    marginLeft: 4,
                  }}
                >
                  {t("panel.objectList.keypoints")}
                </Text>
                <div
                  style={{ display: "flex", flexDirection: "column", gap: 2 }}
                >
                  {shape.keypointParts.map((p, pIdx) => (
                    <div
                      key={p.id}
                      onClick={(e) => {
                        e.stopPropagation();
                        selectKeypointPart(shape.id, p.id);
                      }}
                      style={{
                        display: "flex",
                        justifyContent: "space-between",
                        alignItems: "center",
                        padding: "4px 8px",
                        background:
                          shape.selectedPartId === p.id
                            ? token.colorFillSecondary
                            : "transparent",
                        borderRadius: 4,
                        cursor: "pointer",
                      }}
                    >
                      <Space size={12}>
                        <Text
                          style={{
                            color:
                              p.visibility === 0
                                ? "#ff4d4f"
                                : shape.color || "#1890ff",
                            fontSize: 11,
                            fontWeight: "bold",
                            width: 16,
                          }}
                        >
                          {pIdx + 1}
                        </Text>
                        <Text style={{ color: token.colorText, fontSize: 11 }}>
                          {p.name.toLowerCase()}
                        </Text>
                      </Space>
                      <Space size={2}>
                        {[0, 1, 2].map((v) => (
                          <div
                            key={v}
                            onClick={(e) => {
                              e.stopPropagation();
                              updateKeypointPart(shape.id, p.id, {
                                visibility: v as any,
                              });
                            }}
                            style={{
                              fontSize: 10,
                              width: 22,
                              height: 22,
                              display: "flex",
                              alignItems: "center",
                              justifyContent: "center",
                              borderRadius: 4,
                              cursor: "pointer",
                              fontWeight: "bold",
                              background:
                                p.visibility === v
                                  ? token.colorFillSecondary
                                  : "transparent",
                              color:
                                p.visibility === v
                                  ? token.colorText
                                  : token.colorTextSecondary,
                            }}
                          >
                            {v}
                          </div>
                        ))}
                      </Space>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
      <style>{`.object-class-select .ant-select-selector { padding: 0 !important; color: ${token.colorText} !important; font-size: 11px !important; font-weight: bold; background: ${token.colorFillQuaternary} !important; border-radius: 4px !important; padding-left: 8px !important; border: 1px solid ${token.colorBorderSecondary} !important; } .IconButton { width: 24px; height: 24px; display: flex; align-items: center; justify-content: center; border-radius: 4px; border: 1px solid ${token.colorBorderSecondary}; color: ${token.colorTextDescription}; cursor: pointer; transition: all 0.2s; } .IconButton.active { background: ${token.colorFillSecondary}; color: ${token.colorText}; border-color: ${token.colorPrimaryBorder}; } .object-class-dropdown { background: ${token.colorBgElevated} !important; border: 1px solid ${token.colorBorderSecondary} !important; } .object-class-dropdown .ant-select-item { color: ${token.colorTextSecondary} !important; } .object-class-dropdown .ant-select-item-option-selected { background: ${token.colorPrimaryBg} !important; color: ${token.colorPrimary} !important; } `}</style>
    </div>
  );
}

function IconButton({
  icon,
  active,
  onClick,
}: {
  icon: React.ReactNode;
  active?: boolean;
  onClick: () => void;
}) {
  const { token } = theme.useToken();
  return (
    <div
      className={`IconButton ${active ? "active" : ""}`}
      onClick={(e) => {
        e.stopPropagation();
        onClick();
      }}
      onMouseEnter={(e) =>
        (e.currentTarget.style.background = token.colorFillSecondary)
      }
      onMouseLeave={(e) =>
        (e.currentTarget.style.background = active
          ? token.colorFillSecondary
          : "transparent")
      }
    >
      {icon}
    </div>
  );
}
