import { create } from "zustand";

export type ToolType = 
  | "select" | "rect" | "polygon" | "line" | "keypoint" 
  | "crosshair" | "help" | "brush" | "zoom" | "scissor" 
  | "skeleton" | "measure" | "visibility" | "lock" | "layers"
  | "finish" | "group" | "composite";

export interface KeypointPart {
  id: string;
  name: string;
  x: number; // Relative
  y: number; // Relative
  visibility: 0 | 1 | 2; // 0: none, 1: visible, 2: invisible
}

export interface LabelShape {
  id: string;
  type: ToolType;
  points?: number[]; 
  x?: number;
  y?: number;
  width?: number;
  height?: number;
  classId?: string;
  className?: string;
  color?: string;
  visible?: boolean;
  locked?: boolean;
  zIndex?: number;
  groupId?: string;
  attributes?: Record<string, string | string[]>;
  keypointParts?: KeypointPart[];
  selectedPartId?: string | null;
  selectedPointIndex?: number | null;
  showName?: boolean;
}

export interface LabelingClass {
  id: string;
  name: string;
  color: string;
}

interface LabelingState {
  currentTool: ToolType;
  shapes: LabelShape[];
  selectedShapeIds: string[];
  clipboard: LabelShape[] | null;
  zoom: number;
  showCrosshair: boolean;
  currentImageIndex: number;
  history: LabelShape[][];
  historyIndex: number;
  showLabels: boolean;
  showLabelNames: boolean;
  classes: LabelingClass[];
  isClassModalOpen: boolean;
  activeStatus: "open" | "done";
  defectStatus: "normal" | "defect";
  labelingDefectStatus: "normal" | "defect";
  allShapesByImage: Record<number, LabelShape[]>;
  imageWidth: number;
  imageHeight: number;
  labelingDefectReason: string | null;
  imageDescription: string;
  
  // Actions
  setImageDescription: (desc: string) => void;
  setShowCrosshair: (show: boolean) => void;
  setTool: (tool: ToolType) => void;
  addShape: (shape: LabelShape) => void;
  updateShape: (id: string, updates: Partial<LabelShape>) => void;
  removeShape: (id: string) => void;
  removeAllShapes: () => void;
  selectShape: (id: string | null, multi?: boolean, forceIndividual?: boolean) => void;
  setZoom: (zoom: number) => void;
  setCurrentImageIndex: (index: number) => void;
  setImageSize: (width: number, height: number) => void;
  isFullscreen: boolean;
  toggleFullscreen: () => void;
  undo: () => void; redo: () => void; saveHistory: () => void;
  toggleLabels: () => void; toggleLabelNames: () => void; 
  toggleLock: (id: string) => void;
  toggleVisibility: (id: string) => void;
  toggleObjectLabel: (id: string) => void;
  toggleLockAll: () => void;
  
  setClassModalOpen: (open: boolean) => void; 
  setWorkStatus: (status: "open" | "done") => void;
  toggleDefectStatus: () => void;
  toggleLabelingDefectStatus: () => void;
  toggleWorkStatus: () => void;
  setLabelingDefectReason: (reason: string | null) => void;
  
  copyShapes: () => void;
  cutShapes: () => void;
  pasteShapes: (targetX?: number, targetY?: number) => void;
  groupShapes: () => void;
  ungroupShapes: () => void;
  
  updateKeypointPart: (shapeId: string, partId: string, updates: Partial<KeypointPart>) => void;
  selectKeypointPart: (shapeId: string, partId: string | null) => void;
  selectPolygonPoint: (shapeId: string, pointIndex: number | null) => void;
  deletePolygonPoint: (shapeId: string, pointIndex: number) => void;
  addPolygonPoint: (shapeId: string, pointIndex: number, x: number, y: number) => void;
  bringForward: () => void;
  sendBackward: () => void;
  filters: { invert: boolean; grayscale: boolean; brightness: number; contrast: number; pixelate: number; noise: number; };
  setFilter: (key: string, value: any) => void;
  toggleFilter: (key: string) => void;
  resetFilters: () => void;
  zoomIn: () => void;
  zoomOut: () => void;
  resetZoom: () => void;
  save: () => void;
  pastePreviousShapes: () => void;
  addCompositeShape: (rect: Partial<LabelShape>, kp: Partial<LabelShape>) => void;
}

const skeletonParts = [ "Nose", "Neck", "Right Shoulder", "Right Elbow", "Right Wrist", "Left Shoulder", "Left Elbow", "Left Wrist", "Right Hip", "Right Knee" ];

export const useLabelingStore = create<LabelingState>((set, get) => ({
  currentTool: "select",
  shapes: [],
  selectedShapeIds: [],
  clipboard: null,
  zoom: 1,
  showCrosshair: true,
  currentImageIndex: 0,
  history: [[]],
  historyIndex: 0,
  showLabels: true,
  showLabelNames: true,
  classes: [ { id: "0", name: "지게차", color: "#52c41a" }, { id: "1", name: "작업자", color: "#fadb14" }, { id: "2", name: "중장비", color: "#1890ff" }, { id: "3", name: "기타", color: "#eb2f96" } ],
  isClassModalOpen: false, activeStatus: "open", defectStatus: "normal", labelingDefectStatus: "normal",
  imageWidth: 0, imageHeight: 0,
  labelingDefectReason: null,
  imageDescription: "",
  allShapesByImage: {},
  filters: { invert: false, grayscale: false, brightness: 0, contrast: 0, pixelate: 1, noise: 0 },

  setFilter: (key, value) => set((s) => ({ filters: { ...s.filters, [key]: value } })),
  toggleFilter: (key) => set((s) => ({ filters: { ...s.filters, [key as keyof typeof s.filters]: !s.filters[key as keyof typeof s.filters] } })),
  resetFilters: () => set({ filters: { invert: false, grayscale: false, brightness: 0, contrast: 0, pixelate: 1, noise: 0 } }),
  setImageDescription: (desc) => set({ imageDescription: desc }),
  setShowCrosshair: (show) => set({ showCrosshair: show }),
  setTool: (tool) => set({ currentTool: tool }),
  
  addShape: (shape) => {
    let finalShape = { ...shape, zIndex: get().shapes.length, visible: true, locked: false, showName: true };
    if (shape.type === "polygon" && shape.points && shape.points.length > 0) {
      const xs = shape.points.filter((_, i) => i % 2 === 0); const ys = shape.points.filter((_, i) => i % 2 !== 0);
      finalShape.x = Math.min(...xs); finalShape.y = Math.min(...ys); finalShape.width = Math.max(...xs) - finalShape.x; finalShape.height = Math.max(...ys) - finalShape.y;
    }
    if (shape.type === "keypoint" && shape.x !== undefined && shape.width !== undefined) {
      finalShape.keypointParts = skeletonParts.map((name, i) => { const ratio = i / (skeletonParts.length - 1); return { id: `kp_part_${Date.now()}_${i}`, name, x: shape.width! * ratio, y: shape.height! * ratio, visibility: 1 }; });
    }
    const newShapes = [...get().shapes, finalShape];
    set({ shapes: newShapes, selectedShapeIds: [shape.id], isClassModalOpen: true }); get().saveHistory();
  },
  
  updateShape: (id, updates) => {
    const { selectedShapeIds } = get();
    const targetIds = id ? [id] : selectedShapeIds;
    if (targetIds.length === 0) return;

    set((state) => {
      const newShapes = state.shapes.map((s) => {
        if (!targetIds.includes(s.id)) return s;
        let us = { ...updates };
        // Scale keypoints if needed
        if (s.type === "keypoint" && s.keypointParts && (us.width !== undefined || us.height !== undefined)) {
          const sX = us.width !== undefined ? us.width / (s.width || 1) : 1;
          const sY = us.height !== undefined ? us.height / (s.height || 1) : 1;
          us.keypointParts = s.keypointParts.map(p => ({ ...p, x: p.x * sX, y: p.y * sY }));
        }
        // Scale polygon if needed
        if (s.type === "polygon" && s.points && (us.width !== undefined || us.height !== undefined)) {
          const sX = us.width !== undefined ? us.width / (s.width || 1) : 1;
          const sY = us.height !== undefined ? us.height / (s.height || 1) : 1;
          const dx = (us.x ?? s.x!) - s.x!; const dy = (us.y ?? s.y!) - s.y!;
          us.points = s.points.map((pt, i) => {
            const relPt = i % 2 === 0 ? pt - s.x! : pt - s.y!;
            const scaledRel = i % 2 === 0 ? relPt * sX : relPt * sY;
            return i % 2 === 0 ? (s.x! + dx + scaledRel) : (s.y! + dy + scaledRel);
          });
        }
        return { ...s, ...us };
      });
      return { shapes: newShapes };
    });
    get().saveHistory();
  },
  
  removeShape: (id) => { const newShapes = get().shapes.filter((s) => s.id !== id); set({ shapes: newShapes, selectedShapeIds: get().selectedShapeIds.filter(sid => sid !== id) }); get().saveHistory(); },
  removeAllShapes: () => { set({ shapes: [], selectedShapeIds: [] }); get().saveHistory(); },
  selectShape: (id, multi, forceIndividual) => set((state) => {
    if (!id) return { selectedShapeIds: [] };
    const shape = state.shapes.find(s => s.id === id);
    if (!shape) return state;

    // Find all IDs in the same group if it exists and we're NOT forcing individual selection
    const groupIds = (shape.groupId && !forceIndividual)
      ? state.shapes.filter(s => s.groupId === shape.groupId).map(s => s.id)
      : [id];

    if (multi) {
      const isAnyInSelection = groupIds.some(gid => state.selectedShapeIds.includes(gid));
      if (isAnyInSelection) {
        // Toggle off all in group
        return { selectedShapeIds: state.selectedShapeIds.filter(sid => !groupIds.includes(sid)) };
      } else {
        // Toggle on all in group
        return { selectedShapeIds: [...state.selectedShapeIds, ...groupIds] };
      }
    }
    // Single selection selects entire group
    return { selectedShapeIds: groupIds };
  }),
  setZoom: (zoom) => set({ zoom }), 
  zoomIn: () => set((s) => ({ zoom: Math.min(s.zoom + 0.1, 5) })),
  zoomOut: () => set((s) => ({ zoom: Math.max(s.zoom - 0.1, 0.1) })),
  resetZoom: () => set({ zoom: 1 }),
  save: () => { 
    const { shapes, currentImageIndex, allShapesByImage, defectStatus } = get();
    // Normal save flow first
    const updatedMap = { ...allShapesByImage, [currentImageIndex]: [...shapes] };
    
    // If defect, always keep 'open' status
    if (defectStatus === "defect") { 
      set({ 
        activeStatus: "open", 
        allShapesByImage: updatedMap 
      });
    } else {
      set({ 
        activeStatus: "done", 
        allShapesByImage: updatedMap 
      });
    }
    get().saveHistory(); 
  },
  setCurrentImageIndex: (index) => {
    const { shapes, currentImageIndex, allShapesByImage } = get();
    // Save current
    const updatedMap = { ...allShapesByImage, [currentImageIndex]: [...shapes] };
    // Load new
    const nextShapes = updatedMap[index] || [];
    set({ 
      currentImageIndex: index, 
      shapes: nextShapes, 
      allShapesByImage: updatedMap,
      selectedShapeIds: [], 
      history: [nextShapes], 
      historyIndex: 0, 
      activeStatus: "open", 
      defectStatus: "normal", 
      clipboard: null, 
      imageWidth: 0, 
      imageHeight: 0, 
      filters: { invert: false, grayscale: false, brightness: 0, contrast: 0, pixelate: 1, noise: 0 } 
    });
  },
  setImageSize: (width, height) => set({ imageWidth: width, imageHeight: height }),
  pastePreviousShapes: () => {
    const { currentImageIndex, allShapesByImage, shapes, addShape } = get();
    if (currentImageIndex > 0) {
      const prevShapes = allShapesByImage[currentImageIndex - 1];
      if (prevShapes && prevShapes.length > 0) {
        prevShapes.forEach(s => {
          const newId = `paste_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
          addShape({ ...s, id: newId });
        });
      }
    }
  },
  addCompositeShape: (rect, kp) => {
    const sLen = get().shapes.length;
    const rId = rect.id || `r_${Date.now()}`;
    const kId = kp.id || `k_${Date.now()}`;
    
    let finalRect = { ...rect, id: rId, type: "rect" as ToolType, zIndex: sLen, visible: true, locked: false, showName: true };
    let finalKp = { ...kp, id: kId, type: "keypoint" as ToolType, zIndex: sLen + 1, visible: true, locked: false, showName: true };
    
    // Init keypoints
    if (finalKp.width !== undefined && finalKp.height !== undefined) {
      finalKp.keypointParts = skeletonParts.map((name, i) => { const ratio = i / (skeletonParts.length - 1); return { id: `kp_part_${Date.now()}_${i}`, name, x: finalKp.width! * ratio, y: finalKp.height! * ratio, visibility: 1 }; });
    }
    
    const newShapes = [...get().shapes, finalRect as LabelShape, finalKp as LabelShape];
    set({ shapes: newShapes, selectedShapeIds: [rId, kId], isClassModalOpen: true });
    get().saveHistory();
  },
  saveHistory: () => { const { shapes, history, historyIndex } = get(); const newHistory = history.slice(0, historyIndex + 1); newHistory.push([...shapes]); set({ history: newHistory, historyIndex: newHistory.length - 1 }); },
  undo: () => { const { history, historyIndex } = get(); if (historyIndex > 0) set({ shapes: [...history[historyIndex - 1]], historyIndex: historyIndex - 1, selectedShapeIds: [] }); },
  redo: () => { const { history, historyIndex } = get(); if (historyIndex < history.length - 1) set({ shapes: [...history[historyIndex + 1]], historyIndex: historyIndex + 1, selectedShapeIds: [] }); },
  toggleLabels: () => set((state) => ({ showLabels: !state.showLabels })), toggleLabelNames: () => set((state) => ({ showLabelNames: !state.showLabelNames })),
  toggleLock: (id) => set((state) => ({ shapes: state.shapes.map(s => s.id === id ? { ...s, locked: !s.locked } : s) })), 
  toggleVisibility: (id) => set((state) => ({ shapes: state.shapes.map(s => s.id === id ? { ...s, visible: !s.visible } : s) })), 
  toggleObjectLabel: (id) => set((state) => ({ shapes: state.shapes.map(s => s.id === id ? { ...s, showName: !s.showName } : s) })),
  toggleLockAll: () => set((state) => {
    const anyUnlocked = state.shapes.some(s => !s.locked);
    return { shapes: state.shapes.map(s => ({ ...s, locked: anyUnlocked })) };
  }),
  setClassModalOpen: (open) => set({ isClassModalOpen: open }), 
  setWorkStatus: (status) => set((s) => ({ activeStatus: s.defectStatus === "defect" ? "open" : status })),
  toggleDefectStatus: () => set((state) => {
    const newStatus = state.defectStatus === "normal" ? "defect" : "normal";
    return { defectStatus: newStatus, activeStatus: newStatus === "defect" ? "open" : state.activeStatus };
  }),
  toggleWorkStatus: () => set((state) => {
    if (state.defectStatus === "defect") return { activeStatus: "open" };
    return { activeStatus: state.activeStatus === "open" ? "done" : "open" };
  }),
  toggleLabelingDefectStatus: () => set((state) => {
    const newStatus = state.labelingDefectStatus === "normal" ? "defect" : "normal";
    return { labelingDefectStatus: newStatus, labelingDefectReason: newStatus === "normal" ? null : state.labelingDefectReason };
  }),
  setLabelingDefectReason: (reason) => set({ labelingDefectReason: reason }),
  
  copyShapes: () => { const selected = get().shapes.filter(s => get().selectedShapeIds.includes(s.id)); if (selected.length > 0) set({ clipboard: JSON.parse(JSON.stringify(selected)) }); },
  cutShapes: () => { const selected = get().shapes.filter(s => get().selectedShapeIds.includes(s.id)); if (selected.length > 0) { set({ clipboard: JSON.parse(JSON.stringify(selected)), shapes: get().shapes.filter(s => !get().selectedShapeIds.includes(s.id)), selectedShapeIds: [] }); get().saveHistory(); } },
  
  pasteShapes: (targetX, targetY) => {
    const { clipboard, shapes } = get();
    if (!clipboard || clipboard.length === 0) return;
    
    // Calculate global bounding box of clipboard items
    const minX = Math.min(...clipboard.map(s => s.x || 0));
    const minY = Math.min(...clipboard.map(s => s.y || 0));
    
    // Calculate offset based on target (mouse position) or simple offset
    const dx = targetX !== undefined ? targetX - minX : 20;
    const dy = targetY !== undefined ? targetY - minY : 20;

    const pasted = clipboard.map(s => {
      const newId = `p_${Date.now()}_${Math.random().toString(36).substring(7)}`;
      const ns = { 
        ...s, id: newId, 
        x: (s.x || 0) + dx, 
        y: (s.y || 0) + dy, 
        zIndex: shapes.length 
      };
      if (s.type === "polygon" && s.points) { ns.points = s.points.map((pt, i) => i % 2 === 0 ? pt + dx : pt + dy); }
      if (s.type === "keypoint" && s.keypointParts) { ns.keypointParts = s.keypointParts.map(p => ({ ...p, id: `kp_${newId}_${p.id}` })); }
      return ns;
    });
    set({ shapes: [...shapes, ...pasted], selectedShapeIds: pasted.map(p => p.id) }); get().saveHistory();
  },

  groupShapes: () => { const { selectedShapeIds, shapes } = get(); if (selectedShapeIds.length < 2) return; const gId = `g_${Date.now()}`; set({ shapes: shapes.map(s => selectedShapeIds.includes(s.id) ? { ...s, groupId: gId } : s) }); get().saveHistory(); },
  ungroupShapes: () => { const { selectedShapeIds, shapes } = get(); if (selectedShapeIds.length === 0) return; set({ shapes: shapes.map(s => selectedShapeIds.includes(s.id) ? { ...s, groupId: undefined } : s) }); get().saveHistory(); },

  updateKeypointPart: (shapeId, partId, updates) => {
    set((state) => {
      const shape = state.shapes.find(s => s.id === shapeId); if (!shape || !shape.keypointParts) return state;
      const nP = shape.keypointParts.map(p => p.id === partId ? { ...p, ...updates } : p);
      const absXs = nP.map(p => p.x + (shape.x || 0)); const absYs = nP.map(p => p.y + (shape.y || 0));
      const mX = Math.min(...absXs); const mY = Math.min(...absYs); const MX = Math.max(...absXs); const MY = Math.max(...absYs);
      return { shapes: state.shapes.map(s => s.id === shapeId ? { ...s, x: mX, y: mY, width: MX - mX, height: MY - mY, keypointParts: nP.map(p => ({ ...p, x: (p.x + (shape.x || 0)) - mX, y: (p.y + (shape.y || 0)) - mY })) } : s) };
    });
  },
  selectKeypointPart: (shapeId, partId) => set((state) => ({ shapes: state.shapes.map(s => s.id === shapeId ? { ...s, selectedPartId: partId } : s) })),
  selectPolygonPoint: (shapeId, pI) => set({ shapes: get().shapes.map(s => s.id === shapeId ? { ...s, selectedPointIndex: pI } : s) }),
  deletePolygonPoint: (shapeId, pI) => { set((state) => { const shape = state.shapes.find(s => s.id === shapeId); if (shape && shape.points) { const nP = [...shape.points]; nP.splice(pI * 2, 2); if (nP.length < 4) return { shapes: state.shapes.filter(s => s.id !== shapeId), selectedShapeIds: [] }; const xs = nP.filter((_, i) => i % 2 === 0); const ys = nP.filter((_, i) => i % 2 !== 0); return { shapes: state.shapes.map(s => s.id === shapeId ? { ...s, points: nP, selectedPointIndex: null, x: Math.min(...xs), y: Math.min(...ys), width: Math.max(...xs) - Math.min(...xs), height: Math.max(...ys) - Math.min(...ys) } : s) }; } return state; }); get().saveHistory(); },
  addPolygonPoint: (shapeId, pI, x, y) => { set((state) => { const shape = state.shapes.find(s => s.id === shapeId); if (shape && shape.points) { const nP = [...shape.points]; nP.splice((pI + 1) * 2, 0, x, y); const xs = nP.filter((_, i) => i % 2 === 0); const ys = nP.filter((_, i) => i % 2 !== 0); return { shapes: state.shapes.map(s => s.id === shapeId ? { ...s, points: nP, x: Math.min(...xs), y: Math.min(...ys), width: Math.max(...xs) - Math.min(...xs), height: Math.max(...ys) - Math.min(...ys) } : s) }; } return state; }); get().saveHistory(); },
  bringForward: () => {
    set((state) => {
      const { shapes, selectedShapeIds } = state; if (selectedShapeIds.length === 0) return state;
      const nS = [...shapes]; const selectedIndices = nS.map((s, i) => selectedShapeIds.includes(s.id) ? i : -1).filter(i => i !== -1).sort((a, b) => b - a);
      selectedIndices.forEach(idx => { if (idx < nS.length - 1) { const temp = nS[idx]; nS[idx] = nS[idx + 1]; nS[idx + 1] = temp; } });
      return { shapes: nS };
    }); get().saveHistory();
  },
  sendBackward: () => {
    set((state) => {
      const { shapes, selectedShapeIds } = state; if (selectedShapeIds.length === 0) return state;
      const nS = [...shapes]; const selectedIndices = nS.map((s, i) => selectedShapeIds.includes(s.id) ? i : -1).filter(i => i !== -1).sort((a, b) => a - b);
      selectedIndices.forEach(idx => { if (idx > 0) { const temp = nS[idx]; nS[idx] = nS[idx - 1]; nS[idx - 1] = temp; } });
      return { shapes: nS };
    }); get().saveHistory();
  },
  isFullscreen: false,
  toggleFullscreen: () => set((state) => ({ isFullscreen: !state.isFullscreen })),
}));
