import React, {
  useRef,
  useState,
  useEffect,
  useMemo,
  useCallback,
} from "react";
import { theme, App, Modal, Select, Button, Space, Typography } from "antd";
import {
  Stage,
  Layer,
  Image as KonvaImage,
  Rect,
  Line,
  Group,
  Transformer,
  Circle,
  Text as KonvaText,
} from "react-konva";
import Konva from "konva";
import { useLabelingStore, LabelShape } from "../store/useLabelingStore";
import { useTranslation } from "react-i18next";

const { Text } = Typography;

function useImage(url: string): [HTMLImageElement | undefined] {
  const [image, setImage] = useState<HTMLImageElement | undefined>(undefined);
  useEffect(() => {
    if (!url) return;
    const img = new window.Image();
    img.crossOrigin = "Anonymous";
    img.src = url;
    img.onload = () => setImage(img);
  }, [url]);
  return [image];
}

const generateId = () => {
  if (typeof crypto !== "undefined" && crypto.randomUUID)
    return crypto.randomUUID();
  return Math.random().toString(36).substring(2, 11);
};

interface Props {
  imageUrl: string;
  onShowHelp?: () => void;
}

export default function LabelingStage({ imageUrl, onShowHelp }: Props) {
  const { token } = theme.useToken();
  const { t } = useTranslation("labeling");
  const [image] = useImage(imageUrl);
  const stageRef = useRef<any>(null);
  const imgRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { setImageSize, imageWidth, imageHeight } = useLabelingStore();
  const { message } = App.useApp();

  useEffect(() => {
    if (image) {
      setImageSize(image.naturalWidth, image.naturalHeight);
    }
  }, [image, setImageSize]);

  const shapes = useLabelingStore((s) => s.shapes);
  const currentTool = useLabelingStore((s) => s.currentTool);
  const selectedShapeIds = useLabelingStore((s) => s.selectedShapeIds);
  const zoom = useLabelingStore((s) => s.zoom);
  const setZoom = useLabelingStore((s) => s.setZoom);
  const showCrosshair = useLabelingStore((s) => s.showCrosshair);
  const showLabels = useLabelingStore((s) => s.showLabels);
  const showLabelNames = useLabelingStore((s) => s.showLabelNames);
  const classes = useLabelingStore((s) => s.classes);
  const isClassModalOpen = useLabelingStore((s) => s.isClassModalOpen);
  const setClassModalOpen = useLabelingStore((s) => s.setClassModalOpen);

  const addShape = useLabelingStore((s) => s.addShape);
  const updateShape = useLabelingStore((s) => s.updateShape);
  const selectShape = useLabelingStore((s) => s.selectShape);
  const removeShape = useLabelingStore((s) => s.removeShape);
  const copyShapes = useLabelingStore((s) => s.copyShapes);
  const pasteShapes = useLabelingStore((s) => s.pasteShapes);
  const cutShapes = useLabelingStore((s) => s.cutShapes);
  const addCompositeShape = useLabelingStore((s) => s.addCompositeShape);
  const groupShapes = useLabelingStore((s) => s.groupShapes);
  const ungroupShapes = useLabelingStore((s) => s.ungroupShapes);
  const updateKeypointPart = useLabelingStore((s) => s.updateKeypointPart);
  const selectKeypointPart = useLabelingStore((s) => s.selectKeypointPart);
  const selectPolygonPoint = useLabelingStore((s) => s.selectPolygonPoint);
  const deletePolygonPoint = useLabelingStore((s) => s.deletePolygonPoint);
  const addPolygonPoint = useLabelingStore((s) => s.addPolygonPoint);
  const filters = useLabelingStore((s) => s.filters);
  const toggleFilter = useLabelingStore((s) => s.toggleFilter);
  const setFilter = useLabelingStore((s) => s.setFilter);
  const setTool = useLabelingStore((s) => s.setTool);
  const undo = useLabelingStore((s) => s.undo);
  const redo = useLabelingStore((s) => s.redo);
  const save = useLabelingStore((s) => s.save);
  const resetZoom = useLabelingStore((s) => s.resetZoom);
  const zoomIn = useLabelingStore((s) => s.zoomIn);
  const zoomOut = useLabelingStore((s) => s.zoomOut);
  const bringForward = useLabelingStore((s) => s.bringForward);
  const sendBackward = useLabelingStore((s) => s.sendBackward);
  const toggleLock = useLabelingStore((s) => s.toggleLock);
  const toggleLabels = useLabelingStore((s) => s.toggleLabels);
  const toggleLabelNames = useLabelingStore((s) => s.toggleLabelNames);
  const setCurrentImageIndex = useLabelingStore((s) => s.setCurrentImageIndex);
  const currentImageIndex = useLabelingStore((s) => s.currentImageIndex);
  const pastePreviousShapes = useLabelingStore((s) => s.pastePreviousShapes);

  const [newShape, setNewShape] = useState<LabelShape | null>(null);
  const [stageSize, setStageSize] = useState({ width: 0, height: 0 });
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [drawingPoints, setDrawingPoints] = useState<number[]>([]);
  const [tooltip, setTooltip] = useState<{
    visible: boolean;
    x: number;
    y: number;
    data: any;
  } | null>(null);

  // Calculate active filters list
  const activeFilters = useMemo(() => {
    const list = [];
    if (filters.invert) list.push(Konva.Filters.Invert);
    if (filters.grayscale) list.push(Konva.Filters.Grayscale);
    if (filters.brightness !== 0) list.push(Konva.Filters.Brighten);
    if (filters.contrast !== 0) list.push(Konva.Filters.Contrast);
    if (filters.pixelate > 1) list.push(Konva.Filters.Pixelate);
    if (filters.noise > 0) list.push(Konva.Filters.Noise);
    return list;
  }, [filters]);

  // Sync cache when filters change
  useEffect(() => {
    if (imgRef.current && image) {
      const node = imgRef.current;
      node.cache();
      node.getLayer()?.batchDraw();
    }
  }, [image, filters, zoom]);

  const stateRef = useRef({
    currentTool,
    drawingPoints,
    isClassModalOpen,
    selectedShapeIds,
    shapes,
    classes,
    mousePos,
    currentImageIndex,
    zoom,
    newShape,
    onShowHelp,
    drawingStartPos: null as { x: number; y: number } | null,
  });
  // Performance optimization: throttling for mouse interaction
  const lastMouseMoveTimeRef = useRef(0);

  useEffect(() => {
    stateRef.current = {
      currentTool,
      drawingPoints,
      isClassModalOpen,
      selectedShapeIds,
      shapes,
      classes,
      mousePos,
      currentImageIndex,
      zoom,
      newShape,
      onShowHelp,
      drawingStartPos: stateRef.current.drawingStartPos || null,
    };
  }, [
    currentTool,
    drawingPoints,
    isClassModalOpen,
    selectedShapeIds,
    shapes,
    classes,
    mousePos,
    currentImageIndex,
    zoom,
    newShape,
    onShowHelp,
  ]);

  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current)
        setStageSize({
          width: containerRef.current.clientWidth,
          height: containerRef.current.clientHeight,
        });
    };
    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const finishDrawing = useCallback(() => {
    const { drawingPoints: dp, currentTool: ct } = stateRef.current;
    if (dp.length >= 4) {
      const id = `shape_${Date.now()}`;
      if (ct === "composite") {
        addCompositeShape(
          {
            id: `${id}_rect`,
            x: dp[0],
            y: dp[1],
            width: dp[2] - dp[0],
            height: dp[3] - dp[1],
            color: "#1890ff",
            groupId: id,
          },
          {
            id: `${id}_kp`,
            x: dp[0],
            y: dp[1],
            width: dp[2] - dp[0],
            height: dp[3] - dp[1],
            color: "#52c41a",
            groupId: id,
          },
        );
      } else {
        addShape({
          id,
          type: ct,
          points: [...dp],
          color: ct === "polygon" ? "#eb2f96" : "#1890ff",
        });
      }
      setDrawingPoints([]);
    }
  }, [addShape]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // 0. Input check
      if (
        document.activeElement?.tagName === "INPUT" ||
        document.activeElement?.tagName === "TEXTAREA"
      )
        return;
      const {
        currentTool: ct,
        drawingPoints: dp,
        isClassModalOpen: ico,
        selectedShapeIds: ssids,
        shapes: sList,
        classes: cList,
        mousePos: mPos,
        currentImageIndex,
        zoom,
      } = stateRef.current;
      const primaryId = ssids[0] || null;

      // 1. Tool Selection Shortcuts
      if (e.key === "Escape") {
        setTool("select");
        return;
      }
      if (e.key === "b" || e.key === "B") {
        setTool("rect");
        return;
      }
      if (e.key === "k" || e.key === "K") {
        if (e.altKey) setTool("composite");
        else setTool("keypoint");
        return;
      }
      if (e.key === "p" || e.key === "P") {
        setTool("polygon");
        return;
      }
      if (e.key === "s" || e.key === "S") {
        if (e.shiftKey) save();
        else setTool("skeleton");
        return;
      }
      if (e.key === "g" || e.key === "G") {
        if (e.ctrlKey) groupShapes();
        else setTool("group");
        return;
      }
      if (e.key === "x" || e.key === "X") {
        if (e.ctrlKey) cutShapes();
        else setTool("scissor");
        return;
      }

      // 2. Control Shortcuts
      if (e.key === "l" || e.key === "L") {
        if (primaryId) toggleLock(primaryId);
        return;
      }
      if (e.key === "h" || e.key === "H") {
        toggleLabels();
        return;
      }
      if (e.key === "f" || e.key === "F") {
        toggleLabelNames();
        return;
      }
      if (e.key === "r" || e.key === "R") {
        if (e.ctrlKey) redo();
        else resetZoom();
        return;
      }
      if (e.key === "[") {
        bringForward();
        return;
      }
      if (e.key === "]") {
        sendBackward();
        return;
      }

      // 3. Navigation
      if (e.key === "PageUp") {
        setCurrentImageIndex(Math.max(0, currentImageIndex - 1));
        return;
      }
      if (e.key === "PageDown") {
        setCurrentImageIndex(currentImageIndex + 1);
        return;
      }
      if (e.key === "=" || e.key === "+") {
        zoomIn();
        return;
      }
      if (e.key === "-") {
        zoomOut();
        return;
      }

      // 4. Finish / Edit
      if (e.key === "n" || e.key === "N") {
        if ((ct === "polygon" && dp.length >= 6) || dp.length >= 4)
          finishDrawing();
        return;
      }
      if (e.ctrlKey || e.metaKey) {
        if (e.key === "c" || e.key === "C") {
          e.preventDefault();
          copyShapes();
          message.success(t("msg.copied"));
        } else if (e.key === "v" || e.key === "V") {
          e.preventDefault();
          pasteShapes(mPos.x, mPos.y);
          message.success(t("msg.pasted"));
        } else if (e.key === "z" || e.key === "Z") {
          e.preventDefault();
          undo();
        } else if (e.key === "b" || e.key === "B") {
          e.preventDefault();
          pastePreviousShapes();
          message.success(t("msg.pastedPrev"));
        }
      }

      if (e.key === "Delete" || e.key === "Backspace") {
        const pShape = sList.find((s) => s.id === primaryId);
        if (
          primaryId &&
          pShape?.type === "polygon" &&
          pShape.selectedPointIndex !== null
        ) {
          deletePolygonPoint(primaryId, pShape.selectedPointIndex!);
        } else if (ssids.length > 0) {
          const deletableIds = ssids.filter(
            (id) => !sList.find((s) => s.id === id)?.locked,
          );
          if (deletableIds.length > 0) {
            deletableIds.forEach((id) => removeShape(id));
            message.info(t("msg.deleted"));
          } else {
            message.warning(t("msg.lockedDeleteErr"));
          }
        }
      }

      // 5. Drawing Helpers
      const pShape = sList.find((s) => s.id === primaryId);
      if (
        primaryId &&
        pShape?.type === "polygon" &&
        pShape.selectedPointIndex !== null &&
        (e.key === "a" || e.key === "A") &&
        !pShape.locked
      ) {
        e.preventDefault();
        addPolygonPoint(primaryId, pShape.selectedPointIndex!, mPos.x, mPos.y);
      }

      // 6. Modal / Class Mapping
      if (ico) {
        // Handled within ClassModal for selection-only behavior
      }

      if (e.key === "`") {
        onShowHelp && onShowHelp();
        return;
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [
    finishDrawing,
    copyShapes,
    pasteShapes,
    cutShapes,
    groupShapes,
    ungroupShapes,
    removeShape,
    deletePolygonPoint,
    addPolygonPoint,
    updateShape,
    setClassModalOpen,
    message,
  ]);

  const handleWheel = useCallback((e: any) => {
    if (!e.evt.ctrlKey) return;
    e.evt.preventDefault();
    const stage = stageRef.current;
    if (!stage) return;
    const oldScale = stage.scaleX();
    const ptr = stage.getPointerPosition();
    if (!ptr) return;
    const scaleBy = 1.1;
    const newScale = e.evt.deltaY < 0 ? oldScale * scaleBy : oldScale / scaleBy;
    const mt = {
      x: (ptr.x - stage.x()) / oldScale,
      y: (ptr.y - stage.y()) / oldScale,
    };
    stage.scale({ x: newScale, y: newScale });
    stage.position({ x: ptr.x - mt.x * newScale, y: ptr.y - mt.y * newScale });
    setZoom(newScale);
  }, [setZoom]);

  const handleMouseDown = useCallback((e: any) => {
    if (e.evt.button === 2) {
      e.evt.preventDefault();
      if (stateRef.current.drawingPoints.length > 0) {
        setDrawingPoints([]);
        message.info(t("msg.drawCancel"));
      }
      return;
    }
    if (!stageRef.current) return;
    const pos = stageRef.current.getRelativePointerPosition();
    if (!pos) return;
    if (currentTool === "select") {
      if (e.target === e.target.getStage()) selectShape(null);
      return;
    }
    if (
      (currentTool === "rect" ||
        currentTool === "keypoint" ||
        currentTool === "composite" ||
        currentTool === "group")
    ) {
      stateRef.current.drawingStartPos = { x: pos.x, y: pos.y };
      const id = generateId();
      const nextShape = {
        id,
        type: currentTool,
        x: pos.x,
        y: pos.y,
        width: 0,
        height: 0,
        color: "#1890ff",
      };
      stateRef.current.newShape = nextShape;
      setNewShape(nextShape);
    } else if (currentTool === "polygon" || currentTool === "line") {
      stateRef.current.drawingStartPos = { x: pos.x, y: pos.y };
      setDrawingPoints((prev) => [...prev, pos.x, pos.y]);
    }
  }, [currentTool, selectShape, addShape, message, t]);

  const handleMouseUp = useCallback(() => {
    const { newShape: currShape } = stateRef.current;
    stateRef.current.drawingStartPos = null;
    stateRef.current.newShape = null;
    setNewShape(null);
    if (
      (currentTool === "rect" ||
        currentTool === "keypoint" ||
        currentTool === "composite" ||
        currentTool === "group") &&
      currShape
    ) {
      if (Math.abs(currShape.width || 0) > 5) {
        if (currentTool === "composite") {
          const x = currShape.x!,
            y = currShape.y!,
            w = currShape.width!,
            h = currShape.height!;
          const rX = w < 0 ? x + w : x;
          const rY = h < 0 ? y + h : y;
          const rW = Math.abs(w);
          const rH = Math.abs(h);
          const gid = `comp_${Date.now()}`;
          addCompositeShape(
            {
              id: `${gid}_rect`,
              x: rX,
              y: rY,
              width: rW,
              height: rH,
              color: "#1890ff",
              groupId: gid,
            },
            {
              id: `${gid}_kp`,
              x: rX,
              y: rY,
              width: rW,
              height: rH,
              color: "#52c41a",
              groupId: gid,
            },
          );
          message.success(t("msg.compositeSuccess"));
        } else if (currentTool === "group") {
          // Area Grouping Logic
          const x = currShape.x!,
            y = currShape.y!,
            w = currShape.width!,
            h = currShape.height!;
          const rX = w < 0 ? x + w : x;
          const rY = h < 0 ? y + h : y;
          const rW = Math.abs(w);
          const rH = Math.abs(h);

          const containedIds = shapes
            .filter((s) => {
              if (!s.visible) return false;
              const sx = s.x || 0,
                sy = s.y || 0,
                sw = s.width || 0,
                sh = s.height || 0;
              return (
                sx >= rX && sx + sw <= rX + rW && sy >= rY && sy + sh <= rY + rH
              );
            })
            .map((s) => s.id);

          if (containedIds.length > 1) {
            selectShape(null); // Clear first
            containedIds.forEach((id) => selectShape(id, true)); // Select them
            groupShapes(); // Group them using existing store action
            message.success(
              t("msg.grouped", { count: containedIds.length }),
            );
          } else {
            message.info(t("msg.groupMinErr"));
          }
        } else {
          addShape(currShape);
        }
      }
    }
  }, [currentTool, addShape, addCompositeShape, groupShapes, selectShape, shapes, message, t]);

  const handleMouseMove = useCallback((e: any) => {
    if (!stageRef.current) return;
    const pos = stageRef.current.getRelativePointerPosition();
    if (!pos) return;

    // 1. 성능 최적화: 0.1px 미만 정밀도 무시 & FPS 제한 (약 60fps)
    const prevPos = stateRef.current.mousePos;
    const now = Date.now();
    const isStationary = Math.abs(prevPos.x - pos.x) < 0.1 && Math.abs(prevPos.y - pos.y) < 0.1;
    const isThrottleTimedOut = (now - lastMouseMoveTimeRef.current) > 16;

    stateRef.current.mousePos = pos;
    // 상태를 업데이트해야 하는 상황인지 체크 (드로잉 중이거나 충분한 시간이 지났을 때)
    if (!isStationary && (isThrottleTimedOut || stateRef.current.newShape)) {
      setMousePos(pos);
      lastMouseMoveTimeRef.current = now;
    } else if (isStationary) {
      return;
    }

    const toolsWithDrag = ["rect", "keypoint", "composite", "group"];
    const activeNewShape = stateRef.current.newShape;

    // 2. 드로잉 중일 때만 연산 (Ref를 사용하여 즉각적인 반응성 확보)
    if (toolsWithDrag.includes(currentTool) && activeNewShape) {
      setNewShape((prev) => {
        if (!prev) return null;

        const startX = stateRef.current.drawingStartPos?.x ?? prev.x ?? 0;
        const startY = stateRef.current.drawingStartPos?.y ?? prev.y ?? 0;

        // 좌표 정규화: 드래그 방향에 상관없이 항상 양수의 폭/높이 유지 (IndexSizeError 방지)
        const nextX = Math.min(pos.x, startX);
        const nextY = Math.min(pos.y, startY);
        const nextWidth = Math.max(0.1, Math.abs(pos.x - startX));
        const nextHeight = Math.max(0.1, Math.abs(pos.y - startY));

        // 0.1px 미만 미세 변화면 리렌더링 건너뛰기
        if (
          Math.abs((prev.width || 0) - nextWidth) < 0.1 &&
          Math.abs((prev.height || 0) - nextHeight) < 0.1 &&
          Math.abs((prev.x || 0) - nextX) < 0.1 &&
          Math.abs((prev.y || 0) - nextY) < 0.1
        ) {
          return prev;
        }

        return { ...prev, x: nextX, y: nextY, width: nextWidth, height: nextHeight };
      });
    }
  }, [currentTool]);
  // Sync Stage Scale when store zoom changes (external trigger like toolbar/shortcut)
  useEffect(() => {
    const stage = stageRef.current;
    if (!stage) return;

    const currentScale = stage.scaleX();
    if (Math.abs(currentScale - zoom) < 0.001) return;

    // Zoom to center
    const oldScale = currentScale;
    const newScale = zoom;
    const center = { x: stageSize.width / 2, y: stageSize.height / 2 };
    const mousePointTo = {
      x: (center.x - stage.x()) / oldScale,
      y: (center.y - stage.y()) / oldScale,
    };

    stage.scale({ x: newScale, y: newScale });
    stage.position({
      x: center.x - mousePointTo.x * newScale,
      y: center.y - mousePointTo.y * newScale,
    });
    stage.batchDraw();
  }, [zoom, stageSize]);

  const viewportBounds = useMemo(() => {
    if (!stageSize.width || !stageRef.current)
      return { minX: -5000, maxX: 5000, minY: -5000, maxY: 5000 };
    const stage = stageRef.current;
    const scale = stage.scaleX();
    const x = stage.x();
    const y = stage.y();
    return {
      minX: -x / scale - 5000,
      maxX: (stageSize.width - x) / scale + 5000,
      minY: -y / scale - 5000,
      maxY: (stageSize.height - y) / scale + 5000,
    };
  }, [stageSize, zoom]);

  const isShapeOutOfBounds = (
    shape: LabelShape,
    imgW: number,
    imgH: number,
  ) => {
    if (imgW === 0 || imgH === 0) return false;
    if (shape.type === "rect") {
      const x = shape.x ?? 0;
      const y = shape.y ?? 0;
      return (
        x < 0 ||
        y < 0 ||
        x + (shape.width || 0) > imgW ||
        y + (shape.height || 0) > imgH
      );
    }
    return (
      shape.points?.some((v, i) =>
        i % 2 === 0 ? v < 0 || v > imgW : v < 0 || v > imgH,
      ) || false
    );
  };

  const renderShapes = useMemo(() => {
    if (!showLabels) return [];
    return shapes
      .filter((s) => s.visible)
      .map((shape, idx) => {
        const isSelected = selectedShapeIds.includes(shape.id);
        const isDraggable =
          currentTool === "select" && isSelected && !shape.locked;
        const polyPoints =
          shape.points?.map((pt, i) =>
            i % 2 === 0 ? pt - (shape.x || 0) : pt - (shape.y || 0),
          ) || [];
        const isOut = isShapeOutOfBounds(shape, imageWidth, imageHeight);

        return (
          <Group
            key={shape.id}
            name={`group-${shape.id}`}
            x={shape.x || 0}
            y={shape.y || 0}
            draggable={isDraggable}
            onClick={(e) => {
              e.cancelBubble = true;
              selectShape(
                shape.id,
                e.evt.ctrlKey || e.evt.metaKey,
                e.evt.altKey,
              );
            }}
            onDblClick={(e) => {
              e.cancelBubble = true;
              selectShape(shape.id, false, true); // Force individual selection
            }}
            onDragEnd={(e) => {
              if (shape.locked) return;
              if (shape.type === "rect" || shape.type === "keypoint")
                updateShape(shape.id, { x: e.target.x(), y: e.target.y() });
              else if (shape.type === "polygon" && shape.points) {
                const dx = e.target.x() - (shape.x || 0);
                const dy = e.target.y() - (shape.y || 0);
                const nP = shape.points.map((pt, i) =>
                  i % 2 === 0 ? pt + dx : pt + dy,
                );
                updateShape(shape.id, {
                  x: e.target.x(),
                  y: e.target.y(),
                  points: nP,
                });
              }
            }}
          >
            {shape.type === "rect" ? (
              <Rect
                width={shape.width}
                height={shape.height}
                stroke={isSelected ? "#fff" : isOut ? "#faad14" : shape.color}
                strokeWidth={isSelected ? 3 / zoom : 2 / zoom}
                fill={`${isOut ? "#faad14" : shape.color}${shape.locked ? "11" : "33"}`}
                dash={shape.locked && isSelected ? [5 / zoom, 5 / zoom] : undefined}
                onMouseEnter={(e) => {
                  const stage = e.target.getStage();
                  const ptr = stage?.getPointerPosition();
                  if (ptr) {
                    setTooltip({
                      visible: true,
                      x: ptr.x + 15,
                      y: ptr.y + 15,
                      data: {
                        type: shape.type,
                        pos: `[${(shape.x || 0).toFixed(2)}, ${(shape.y || 0).toFixed(2)}]`,
                        className: shape.className,
                        attrName: "workspace.stage.accidentType",
                        attrValue: "workspace.stage.fall",
                      },
                    });
                  }
                }}
                onMouseLeave={() => setTooltip(null)}
              />
            ) : null}
            {shape.type === "polygon" ? (
              <Group>
                <Line
                  points={polyPoints}
                  closed
                  stroke={isSelected ? "#fff" : isOut ? "#faad14" : shape.color}
                  strokeWidth={isSelected ? 3 / zoom : 2 / zoom}
                  fill={`${isOut ? "#faad14" : shape.color}${shape.locked ? "22" : "55"}`}
                  dash={shape.locked && isSelected ? [5 / zoom, 5 / zoom] : undefined}
                  onMouseEnter={(e) => {
                    const stage = e.target.getStage();
                    const ptr = stage?.getPointerPosition();
                    if (ptr) {
                      setTooltip({
                        visible: true,
                        x: ptr.x + 15,
                        y: ptr.y + 15,
                        data: {
                          type: shape.type,
                          pos: `[${(shape.x || 0).toFixed(2)}, ${(shape.y || 0).toFixed(2)}]`,
                          className: shape.className,
                          attrName: "workspace.stage.accidentType",
                          attrValue: "workspace.stage.fall",
                        },
                      });
                    }
                  }}
                  onMouseLeave={() => setTooltip(null)}
                />
                {isSelected && shape.points
                  ? Array.from({ length: shape.points.length / 2 }).map(
                    (_, i) => (
                      <Circle
                        key={i}
                        x={shape.points![i * 2] - (shape.x || 0)}
                        y={shape.points![i * 2 + 1] - (shape.y || 0)}
                        radius={
                          isSelectedVertex(shape, i) ? 6 / zoom : 4 / zoom
                        }
                        fill={isSelectedVertex(shape, i) ? "#fff" : "#eb2f96"}
                        stroke="#fff"
                        strokeWidth={
                          isSelectedVertex(shape, i) ? 2 / zoom : 1 / zoom
                        }
                        draggable={!shape.locked}
                        onDragEnd={(e) => {
                          e.cancelBubble = true;
                          const nP = [...shape.points!];
                          nP[i * 2] = e.target.x() + (shape.x || 0);
                          nP[i * 2 + 1] = e.target.y() + (shape.y || 0);
                          updateShape(shape.id, {
                            points: nP,
                            ...recalcPolygonBox(nP),
                          });
                        }}
                        onClick={(e) => {
                          e.cancelBubble = true;
                          selectShape(shape.id);
                          selectPolygonPoint(shape.id, i);
                        }}
                      />
                    ),
                  )
                  : null}
              </Group>
            ) : null}
            {shape.type === "keypoint" ? (
              <Group>
                <Rect
                  width={shape.width}
                  height={shape.height}
                  stroke={isOut ? "#faad14" : "#1890ff"}
                  strokeWidth={2 / zoom}
                  dash={[4 / zoom, 4 / zoom]}
                  opacity={isSelected ? 0.3 : 0.8}
                />
                {shape.keypointParts ? (
                  <Line
                    points={shape.keypointParts.flatMap((p) => [p.x, p.y])}
                    stroke={isOut ? "#faad14" : "#ff4d4f"}
                    strokeWidth={3 / zoom}
                    lineCap="round"
                    lineJoin="round"
                  />
                ) : null}
                {shape.keypointParts?.map((p) => (
                  <Circle
                    key={p.id}
                    x={p.x}
                    y={p.y}
                    radius={isSelected ? 7 / zoom : 6 / zoom}
                    fill={
                      p.visibility === 1
                        ? "#52c41a"
                        : p.visibility === 2
                          ? "rgba(255,255,255,0.2)"
                          : "#ff4d4f"
                    }
                    stroke="#fff"
                    strokeWidth={1.5 / zoom}
                    draggable={!shape.locked}
                    onMouseEnter={(e) => {
                      const stage = e.target.getStage();
                      const ptr = stage?.getPointerPosition();
                      if (ptr) {
                        setTooltip({
                          visible: true,
                          x: ptr.x + 15,
                          y: ptr.y + 15,
                          data: {
                            type: "keypoint",
                            pos: `[${(p.x + (shape.x || 0)).toFixed(2)}, ${(p.y + (shape.y || 0)).toFixed(2)}]`,
                            className: shape.className,
                            keypointName: p.name,
                            visibility: p.visibility,
                            attrName: "workspace.stage.accidentType",
                            attrValue: "workspace.stage.fall",
                          },
                        });
                      }
                    }}
                    onMouseLeave={() => setTooltip(null)}
                    onDragEnd={(e) => {
                      e.cancelBubble = true;
                      updateKeypointPart(shape.id, p.id, {
                        x: e.target.x(),
                        y: e.target.y(),
                      });
                    }}
                    onClick={(e) => {
                      e.cancelBubble = true;
                      selectShape(shape.id);
                      selectKeypointPart(shape.id, p.id);
                    }}
                  />
                ))}
              </Group>
            ) : null}
            {showLabelNames && shape.showName ? (
              <Group y={-16 / zoom}>
                <Rect
                  fill={isOut ? "#faad14" : shape.color}
                  width={(isOut ? 100 : 80) / zoom}
                  height={16 / zoom}
                />
                <KonvaText
                  text={`${isOut ? "⚠️ " : ""}${idx + 1}: ${shape.className || shape.type
                    }${shape.locked ? " (🔒)" : ""}`}
                  fill="#fff"
                  fontSize={11 / zoom}
                  padding={2 / zoom}
                />
              </Group>
            ) : null}
          </Group>
        );
      });
  }, [
    shapes,
    showLabels,
    showLabelNames,
    selectedShapeIds,
    currentTool,
    zoom,
    selectShape,
    updateShape,
    updateKeypointPart,
    selectKeypointPart,
    selectPolygonPoint,
    imageWidth,
    imageHeight,
  ]);

  return (
    <div
      ref={containerRef}
      onContextMenu={(e) => e.preventDefault()}
      style={{
        width: "100%",
        height: "100%",
        background: token.colorBgContainer,
        cursor: currentTool === "select" ? "default" : "crosshair",
        overflow: "hidden",
        position: "relative",
      }}
    >

      <Stage
        width={stageSize.width}
        height={stageSize.height}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        ref={stageRef}
        draggable={currentTool === "select" && selectedShapeIds.length === 0}
      >
        <Layer>
          {image ? (
            <KonvaImage
              image={image}
              width={image.width}
              height={image.height}
              ref={imgRef}
              filters={activeFilters}
              brightness={filters.brightness}
              contrast={filters.contrast}
              pixelSize={filters.pixelate}
              noise={filters.noise}
            />
          ) : null}

          {/* Render Persistent Group Boundaries */}
          {useMemo(() => {
            const groups: Record<string, LabelShape[]> = {};
            shapes.forEach((s) => {
              if (s.groupId) {
                if (!groups[s.groupId]) groups[s.groupId] = [];
                groups[s.groupId].push(s);
              }
            });
            return Object.entries(groups).map(([gid, members]) => {
              if (members.length < 2) return null;
              const xs = members.flatMap((m) => [
                m.x || 0,
                (m.x || 0) + (m.width || 0),
              ]);
              const ys = members.flatMap((m) => [
                m.y || 0,
                (m.y || 0) + (m.height || 0),
              ]);
              const minX = Math.min(...xs);
              const minY = Math.min(...ys);
              const maxX = Math.max(...xs);
              const maxY = Math.max(...ys);
              return (
                <Rect
                  key={`group-boundary-${gid}`}
                  x={minX - 4 / zoom}
                  y={minY - 4 / zoom}
                  width={maxX - minX + 8 / zoom}
                  height={maxY - minY + 8 / zoom}
                  stroke="rgba(82, 196, 26, 0.6)"
                  strokeWidth={1 / zoom}
                  dash={[4 / zoom, 4 / zoom]}
                  fill="transparent"
                  listening={true}
                  onClick={(e) => {
                    e.cancelBubble = true;
                    const memberIds = members.map((m) => m.id);
                    if (memberIds.length > 0) selectShape(memberIds[0]);
                  }}
                />
              );
            });
          }, [shapes, zoom, selectShape])}

          {renderShapes}
          {newShape &&
            (newShape.type === "rect" ||
              newShape.type === "keypoint" ||
              newShape.type === "composite" ||
              newShape.type === "group") ? (
            <Group>
              <Rect
                x={newShape.x}
                y={newShape.y}
                width={newShape.width}
                height={newShape.height}
                stroke={newShape.type === "group" ? "#52c41a" : "#1890ff"}
                strokeWidth={3 / zoom}
                dash={
                  newShape.type === "group" ? [8 / zoom, 4 / zoom] : undefined
                }
                fill={
                  newShape.type === "group"
                    ? "rgba(82, 196, 26, 0.25)"
                    : "rgba(24, 144, 255, 0.05)"
                }
                cornerRadius={2 / zoom}
              />
              <KonvaText
                x={newShape.x}
                y={(newShape.y || 0) - 20 / zoom}
                text={
                  newShape.type === "group"
                    ? t("workspace.stage.grouping")
                    : newShape.type === "composite"
                      ? t("workspace.stage.autoPolygon")
                      : ""
                }
                fontSize={12 / zoom}
                fill={newShape.type === "group" ? "#52c41a" : "#1890ff"}
                fontStyle="bold"
              />
            </Group>
          ) : null}
          {drawingPoints.length > 0 ? (
            <Group>
              <Line
                points={[...drawingPoints, mousePos.x, mousePos.y]}
                stroke="#eb2f96"
                strokeWidth={2 / zoom}
                dash={[5 / zoom, 5 / zoom]}
              />
              {Array.from({ length: drawingPoints.length / 2 }).map((_, i) => (
                <Circle
                  key={i}
                  x={drawingPoints[i * 2]}
                  y={drawingPoints[i * 2 + 1]}
                  radius={4 / zoom}
                  fill="#fff"
                />
              ))}
            </Group>
          ) : null}
          {selectedShapeIds.length > 0 ? (
            <MultiShapeTransformer
              ids={selectedShapeIds}
              zoom={zoom}
              shapes={shapes}
              updateShape={updateShape}
            />
          ) : null}
          {showCrosshair ? (
            <Group listening={false}>
              <Line
                points={[
                  viewportBounds.minX,
                  mousePos.y,
                  viewportBounds.maxX,
                  mousePos.y,
                ]}
                stroke="#ff4d4f"
                strokeWidth={0.5 / zoom}
                opacity={0.6}
              />
              <Line
                points={[
                  mousePos.x,
                  viewportBounds.minY,
                  mousePos.x,
                  viewportBounds.maxY,
                ]}
                stroke="#ff4d4f"
                strokeWidth={0.5 / zoom}
                opacity={0.6}
              />
            </Group>
          ) : null}
        </Layer>
      </Stage>
      {tooltip && tooltip.visible && (
        <div
          style={{
            position: "absolute",
            top: tooltip.y,
            left: tooltip.x,
            background: token.colorBgElevated,
            border: `1px solid ${token.colorBorderSecondary}`,
            borderRadius: 4,
            padding: "12px",
            zIndex: 1000,
            pointerEvents: "none",
            boxShadow: token.boxShadowSecondary,
            minWidth: 200,
          }}
        >
          <TooltipRow
            label={t("workspace.stage.type", { ns: "labeling" })}
            value={t(`workspace.stage.${tooltip.data.type}`, { ns: "labeling" })}
          />
          <TooltipRow
            label={t("workspace.stage.position", { ns: "labeling" })}
            value={tooltip.data.pos}
          />
          <TooltipRow
            label={t("workspace.stage.className", { ns: "labeling" })}
            value={tooltip.data.className}
          />
          <TooltipRow
            label={t("workspace.stage.attrName", { ns: "labeling" })}
            value={tooltip.data.attrName ? t(tooltip.data.attrName, { ns: "labeling" }) : ""}
          />
          <TooltipRow
            label={t("workspace.stage.attrValue", { ns: "labeling" })}
            value={tooltip.data.attrValue ? t(tooltip.data.attrValue, { ns: "labeling" }) : ""}
          />
          {tooltip.data.type === "keypoint" && (
            <>
              <TooltipRow
                label={t("workspace.stage.kpName", { ns: "labeling" })}
                value={tooltip.data.keypointName}
              />
              <TooltipRow
                label={t("workspace.stage.visibilityLevel", { ns: "labeling" })}
                value={
                  tooltip.data.visibility
                    ? t(`workspace.stage.visible${tooltip.data.visibility}`, {
                        ns: "labeling",
                      })
                    : ""
                }
              />
            </>
          )}
        </div>
      )}
      <ClassModal />
    </div>
  );
}

function TooltipRow({ label, value }: { label: string; value: string }) {
  const { token } = theme.useToken();
  return (
    <div
      style={{
        display: "flex",
        gap: 12,
        marginBottom: 4,
        fontSize: 11,
        alignItems: "center",
      }}
    >
      <span style={{ color: token.colorTextDescription, minWidth: 70 }}>
        {label}
      </span>
      <span style={{ color: token.colorText, fontWeight: "500" }}>
        : {value}
      </span>
    </div>
  );
}

function ClassModal() {
  const { token } = theme.useToken();
  const { t } = useTranslation(["labeling", "common"]);
  const {
    classes,
    isClassModalOpen,
    setClassModalOpen,
    selectedShapeIds,
    updateShape,
    removeShape,
    shapes,
  } = useLabelingStore();
  const [classValue, setClassValue] = useState<string | undefined>(undefined);

  useEffect(() => {
    if (!isClassModalOpen) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      const num = parseInt(e.key);
      if (!isNaN(num) && num >= 0 && num < classes.length) {
        e.preventDefault();
        setClassValue(classes[num].id);
      }
      if (e.key === "Enter" && classValue) {
        e.preventDefault();
        handleClassSubmit();
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [isClassModalOpen, classes, classValue]);
  const primaryId = selectedShapeIds[0];
  const primaryShape = shapes.find((s) => s.id === primaryId);

  const handleClassSubmit = () => {
    if (classValue && selectedShapeIds.length > 0) {
      const cls = classes.find((c) => c.id === classValue);
      if (cls) {
        selectedShapeIds.forEach((id) =>
          updateShape(id, {
            classId: cls.id,
            className: cls.name,
            color: cls.color,
          }),
        );
        setClassModalOpen(false);
        setClassValue(undefined);
      }
    }
  };

  const handleCancel = () => {
    selectedShapeIds.forEach((id) => {
      const s = shapes.find((sh) => sh.id === id);
      if (s && !s.classId) removeShape(id);
    });
    setClassModalOpen(false);
    setClassValue(undefined);
  };

  return (
    <Modal
      title={t("modal.classSelect", { ns: "labeling" })}
      open={isClassModalOpen}
      onOk={handleClassSubmit}
      onCancel={handleCancel}
      okText={t("common:apply")}
      cancelText={t("common:cancel")}
      okButtonProps={{ disabled: !classValue }}
      width={320}
      styles={{ body: { padding: 20, background: token.colorBgContainer } }}
      wrapClassName="dark-modal"
    >
      <div style={{ marginBottom: 16 }}>
        <div
          style={{
            color: token.colorTextDescription,
            fontSize: 12,
            marginBottom: 4,
          }}
        >
          {t("modal.classNm", { ns: "labeling" })}
        </div>
        <Select
          style={{ width: "100%" }}
          placeholder={t("modal.classPlaceholder", { ns: "labeling" })}
          styles={{ popup: { root: { background: token.colorBgElevated } } }}
          onChange={setClassValue}
          value={classValue}
        >
          {classes.map((c, i) => (
            <Select.Option
              key={c.id}
              value={c.id}
              style={{ color: token.colorText }}
            >
              {i}: {c.name}
            </Select.Option>
          ))}
        </Select>
      </div>
    </Modal>
  );
}

function isSelectedVertex(shape: LabelShape, index: number) {
  return shape.selectedPointIndex === index;
}
function recalcPolygonBox(pts: number[]) {
  const xs = pts.filter((_, i) => i % 2 === 0);
  const ys = pts.filter((_, i) => i % 2 !== 0);
  const minX = Math.min(...xs);
  const minY = Math.min(...ys);
  return {
    x: minX,
    y: minY,
    width: Math.max(...xs) - minX,
    height: Math.max(...ys) - minY,
  };
}

function MultiShapeTransformer({
  ids,
  zoom,
  shapes,
  updateShape,
}: {
  ids: string[];
  zoom: number;
  shapes: LabelShape[];
  updateShape: any;
}) {
  const { token } = theme.useToken();
  const trRef = useRef<any>(null);
  useEffect(() => {
    if (trRef.current) {
      const stage = trRef.current.getStage();
      if (stage) {
        const nodes = ids
          .filter((id) => !shapes.find((s) => s.id === id)?.locked) // Filter out locked shapes
          .map((id) => stage.findOne(`.group-${id}`))
          .filter(Boolean);
        trRef.current.nodes(nodes);
        trRef.current.getLayer()?.batchDraw();
      }
    }
  }, [ids, shapes]);
  return (
    <Transformer
      ref={trRef}
      rotateEnabled={false}
      anchorFill={token.colorBgContainer}
      anchorStroke={token.colorPrimary}
      borderStroke={token.colorPrimary}
      anchorSize={8 / zoom}
      keepRatio={true}
      ignoreStroke={true}
      onTransformEnd={() => {
        const tr = trRef.current;
        if (!tr) return;
        const nodes = tr.nodes();
        if (!nodes) return;
        nodes.forEach((node: any) => {
          const id = node.name().replace("group-", "");
          const shape = shapes.find((s) => s.id === id);
          if (shape && !shape.locked) {
            const sX = node.scaleX();
            const sY = node.scaleY();
            node.setAttrs({ scaleX: 1, scaleY: 1 });
            updateShape(id, {
              x: node.x(),
              y: node.y(),
              width: (shape.width || 0) * sX,
              height: (shape.height || 0) * sY,
            });
          }
        });
      }}
    />
  );
}
