import {
  theme, Button, Tooltip, Space, Divider, Popover, Menu, Slider, Typography
} from "antd";
import { useTranslation } from "react-i18next";
import {
  SelectOutlined, QuestionCircleOutlined,
  DeploymentUnitOutlined, DotChartOutlined, NodeIndexOutlined, DiffOutlined, GroupOutlined,
  ScissorOutlined, CopyOutlined, SnippetsOutlined, DeleteOutlined, RestOutlined,
  EyeOutlined, EyeInvisibleOutlined, FontSizeOutlined, LockOutlined, InsertRowAboveOutlined,
  LeftOutlined, RightOutlined,
  ZoomInOutlined, ZoomOutOutlined, FullscreenExitOutlined, FullscreenOutlined,
  RollbackOutlined, RedoOutlined, SaveOutlined, LogoutOutlined,
  ArrowUpOutlined, ArrowDownOutlined,
  FilterOutlined, BgColorsOutlined, SelectOutlined as InvertIcon, ReloadOutlined,
  EditOutlined, PictureOutlined as ImageControlIcon
} from "@ant-design/icons";
import { useLabelingStore } from "../store/useLabelingStore";

const { Text } = Typography;

export default function LabelingToolbar({ onShowHelp, onExit }: { onShowHelp: () => void; onExit: () => void }) {
  const { token } = theme.useToken();
  const {
    currentTool, setTool, undo, redo, bringForward, sendBackward,
    currentImageIndex, setCurrentImageIndex, showLabels, toggleLabels,
    showLabelNames, toggleLabelNames, zoomIn, zoomOut, resetZoom, save,
    pastePreviousShapes, filters, setFilter, toggleFilter, resetFilters,
    copyShapes, pasteShapes, removeShape, selectedShapeIds,
    toggleLockAll, shapes, removeAllShapes, isFullscreen, toggleFullscreen
  } = useLabelingStore();
  const { t } = useTranslation("labeling");

  // Custom BBox Icon
  const BboxIcon = () => (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <rect x="3" y="3" width="18" height="18" />
      <circle cx="3" cy="3" r="2.5" fill="currentColor" stroke="none" />
      <circle cx="21" cy="3" r="2.5" fill="currentColor" stroke="none" />
      <circle cx="3" cy="21" r="2.5" fill="currentColor" stroke="none" />
      <circle cx="21" cy="21" r="2.5" fill="currentColor" stroke="none" />
    </svg>
  );

  const labelingMenu = (
    <div style={{
      background: token.colorBgElevated, border: `1px solid ${token.colorBorderSecondary}`,
      padding: "4px", borderRadius: 8, display: "flex", flexDirection: "column", gap: "2px", boxShadow: token.boxShadowSecondary
    }}>
      <ToolbarButton icon={<BboxIcon />} label={t('toolbar.bbox')} onClick={() => setTool("rect")} active={currentTool === "rect"} />
      <ToolbarButton icon={<DotChartOutlined />} label={t('toolbar.keypoint')} onClick={() => setTool("keypoint")} active={currentTool === "keypoint"} />
      <ToolbarButton icon={<DeploymentUnitOutlined />} label={t('toolbar.polygon')} onClick={() => setTool("polygon")} active={currentTool === "polygon"} />
      <ToolbarButton icon={<NodeIndexOutlined />} label={t('toolbar.skeleton')} onClick={() => setTool("skeleton")} active={currentTool === "skeleton"} />
      <ToolbarButton icon={<GroupOutlined />} label={t('toolbar.composite')} onClick={() => setTool("composite")} active={currentTool === "composite"} />
    </div>
  );

  const filterMenu = (
    <Menu theme="dark" style={{ background: token.colorBgElevated, border: `1px solid ${token.colorBorderSecondary}`, padding: "12px", width: 220 }}>
      <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <Text style={{ color: token.colorTextDescription, fontSize: 11 }}>{t('panel.filters') || 'Filters'}</Text>
          <Button type="link" size="small" icon={<ReloadOutlined />} onClick={resetFilters} style={{ fontSize: 10 }}>{t('common.reset') || 'Reset'}</Button>
        </div>
        <div style={{ display: "flex", gap: 12 }}>
          <Button size="small" type={filters.invert ? "primary" : "default"} icon={<InvertIcon style={{ transform: 'rotate(180deg)' }} />} onClick={() => toggleFilter('invert')} />
          <Button size="small" type={filters.grayscale ? "primary" : "default"} icon={<BgColorsOutlined />} onClick={() => toggleFilter('grayscale')} />
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          <FilterControl label={t('page.brightness') || 'Brightness'} value={Math.round(filters.brightness * 100)} onChange={(v) => setFilter('brightness', v / 100)} token={token} />
          <FilterControl label={t('page.contrast') || 'Contrast'} value={filters.contrast} min={-100} max={100} onChange={(v) => setFilter('contrast', v)} token={token} />
        </div>
      </div>
    </Menu>
  );

  const editMenu = (
    <div style={{
      background: token.colorBgElevated, border: `1px solid ${token.colorBorderSecondary}`,
      padding: "4px", borderRadius: 8, display: "flex", flexDirection: "column", gap: "2px", boxShadow: token.boxShadowSecondary
    }}>
      <ToolbarButton icon={<ScissorOutlined />} label={t('toolbar.scissor')} onClick={() => setTool("scissor")} active={currentTool === "scissor"} />
      <ToolbarButton icon={<CopyOutlined />} label={t('toolbar.copy')} onClick={copyShapes} />
      <ToolbarButton icon={<SnippetsOutlined />} label={t('toolbar.paste')} onClick={() => pasteShapes()} />
      <ToolbarButton icon={<InsertRowAboveOutlined />} label={t('toolbar.pastePrev')} onClick={pastePreviousShapes} />
      <Divider style={{ margin: "2px 0", borderColor: token.colorBorderSecondary }} />
      <ToolbarButton icon={<DiffOutlined />} label={t('toolbar.group')} onClick={() => setTool("group")} active={currentTool === "group"} />
      <ToolbarButton icon={<ArrowUpOutlined />} label={t('toolbar.bringForward')} onClick={bringForward} />
      <ToolbarButton icon={<ArrowDownOutlined />} label={t('toolbar.sendBackward')} onClick={sendBackward} />
      <Divider style={{ margin: "2px 0", borderColor: token.colorBorder }} />
      <ToolbarButton icon={<DeleteOutlined />} label={t('toolbar.deleteSelected')} onClick={() => selectedShapeIds.forEach(id => removeShape(id))} color={token.colorError} />
      <ToolbarButton icon={<RestOutlined />} label={t('toolbar.deleteAll')} onClick={removeAllShapes} color={token.colorError} />
    </div>
  );

  const imageControlMenu = (
    <div style={{ display: "flex", flexDirection: "column", gap: "2px", padding: "4px" }}>
      <ToolbarButton icon={<LeftOutlined />} label={t('toolbar.prevImage')} onClick={() => setCurrentImageIndex(currentImageIndex - 1)} />
      <ToolbarButton icon={<RightOutlined />} label={t('toolbar.nextImage')} onClick={() => setCurrentImageIndex(currentImageIndex + 1)} />
      <Divider style={{ margin: "4px 0", borderColor: token.colorBorderSecondary }} />
      <ToolbarButton icon={<ZoomInOutlined />} label={t('toolbar.zoomIn')} onClick={zoomIn} />
      <ToolbarButton icon={<ZoomOutOutlined />} label={t('toolbar.zoomOut')} onClick={zoomOut} />
      <ToolbarButton icon={<FullscreenExitOutlined />} label={t('toolbar.zoomReset')} onClick={resetZoom} />
      <Divider style={{ margin: "4px 0", borderColor: token.colorBorderSecondary }} />
      <ToolbarButton
        icon={showLabels ? <EyeOutlined /> : <EyeInvisibleOutlined />}
        label={showLabels ? t('toolbar.hideLabels') : t('toolbar.showLabels')}
        onClick={toggleLabels}
        active={!showLabels}
      />
      <ToolbarButton
        icon={<FontSizeOutlined />}
        label={showLabelNames ? t('toolbar.hideNames') : t('toolbar.showNames')}
        onClick={toggleLabelNames}
        active={!showLabelNames}
      />
      <ToolbarButton
        icon={<LockOutlined />}
        label={t('toolbar.lockAll')}
        onClick={toggleLockAll}
        active={shapes.length > 0 && shapes.every(s => s.locked)}
      />
    </div>
  );

  return (
    <div style={{
      display: "flex", flexDirection: "column", alignItems: "center", gap: "2px",
      width: "48px", padding: "8px 0", height: "100%", background: token.colorBgContainer, borderRight: `1px solid ${token.colorBorderSecondary}`
    }}>
      <ToolbarButton icon={<QuestionCircleOutlined />} label={t('toolbar.help')} onClick={onShowHelp} />
      <ToolbarButton icon={<SelectOutlined />} label={t('toolbar.cursor')} onClick={() => setTool("select")} active={currentTool === "select"} />

      <Divider style={{ margin: "4px 0", borderColor: token.colorBorderSecondary }} />

      <Popover content={labelingMenu} placement="rightTop" trigger="hover" arrow={false} styles={{ content: { margin: -10, }, }} >
        <div style={{ width: "100%", display: "flex", justifyContent: "center" }}>
          <ToolbarButton icon={<EditOutlined />} label={t('toolbar.labelingTools')} active={currentTool !== "select" && currentTool !== "scissor"} tooltipDisabled />
        </div>
      </Popover>

      <Popover content={editMenu} placement="rightTop" trigger="hover" arrow={false} styles={{ content: { margin: -10, }, }}>
        <div style={{ width: "100%", display: "flex", justifyContent: "center" }}>
          <ToolbarButton icon={<ScissorOutlined />} label={t('toolbar.editTools')} active={currentTool === "scissor"} tooltipDisabled />
        </div>
      </Popover>

      <Popover content={imageControlMenu} placement="rightTop" trigger="hover" arrow={false} styles={{ content: { margin: -10, }, }}>
        <div style={{ width: "100%", display: "flex", justifyContent: "center" }}>
          <ToolbarButton icon={<ImageControlIcon />} label={t('toolbar.displayControl') || 'Display Control'} tooltipDisabled />
        </div>
      </Popover>

      <div style={{ flex: 1 }} />

      <ToolbarButton
        icon={isFullscreen ? <FullscreenExitOutlined /> : <FullscreenOutlined />}
        label={isFullscreen ? t('toolbar.exitFullscreen') : t('toolbar.fullscreen')}
        onClick={toggleFullscreen}
        active={isFullscreen}
      />
      <ToolbarButton icon={<RollbackOutlined />} label={t('toolbar.undo')} onClick={undo} />
      <ToolbarButton icon={<RedoOutlined />} label={t('toolbar.redo')} onClick={redo} />
      <ToolbarButton icon={<SaveOutlined />} label={t('toolbar.save')} onClick={save} color={token.colorPrimary} />
      <ToolbarButton icon={<LogoutOutlined />} label={t('toolbar.exit')} onClick={onExit} />
    </div >
  );
}

function ToolbarButton({ icon, label, onClick, active, color, tooltipDisabled }: { icon: any, label: string, onClick?: () => void, active?: boolean, color?: string, tooltipDisabled?: boolean }) {
  const { token } = theme.useToken();
  const btn = (
    <Button
      type={active ? "primary" : "text"}
      icon={icon}
      onClick={onClick}
      style={{
        color: active ? token.colorTextLightSolid : (color || token.colorTextSecondary),
        fontSize: "18px", height: "36px", width: "40px",
        display: "flex", alignItems: "center", justifyContent: "center"
      }}
    />
  );

  if (tooltipDisabled) return btn;

  return (
    <Tooltip title={label} placement="right">
      {btn}
    </Tooltip>
  );
}

function FilterControl({ label, value, onChange, min = -100, max = 100, token }: { label: string, value: number, onChange: (v: number) => void, min?: number, max?: number, token: any }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <Text style={{ color: token.colorTextDescription, fontSize: 10 }}>{label}</Text>
        <Text style={{ color: token.colorText, fontSize: 10 }}>{value}</Text>
      </div>
      <Slider
        value={value} min={min} max={max} onChange={onChange}
        styles={{ rail: { background: token.colorFillQuaternary }, handle: { background: token.colorPrimary } }}
      />
    </div>
  );
}
