import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { 
  theme, Card, Table, Button, Space, Typography, 
  Progress, Breadcrumb, App 
} from "antd";
import { 
  InfoCircleOutlined, HomeOutlined, DesktopOutlined,
} from "@ant-design/icons";
import WorkPage from "./WorkPage";
import { getMockLabelingJobs, LabelingJobRecord } from "../../mocks/jobs";
import { useLabelingStore } from "../../store/useLabelingStore";

const { useToken } = theme;
const { Title, Text } = Typography;

export default function LabelingListPage() {
  const { token } = useToken();
  const { t } = useTranslation(["labeling", "common", "project"]);
  const [isWorkMode, setIsWorkMode] = useState(false);
  const [selectedJob, setSelectedJob] = useState<LabelingJobRecord | null>(null);

  const handleEnterWork = (record: LabelingJobRecord) => { setSelectedJob(record); setIsWorkMode(true); };
  const handleBackToList = () => { setIsWorkMode(false); setSelectedJob(null); };
  const { isFullscreen } = useLabelingStore();

  const mockJobList = getMockLabelingJobs(t);

  if (isWorkMode) {
    return (
      <App style={{ height: "100%", width: "100%", display: "flex", flexDirection: "column" }}>
        <div style={{ 
          margin: isFullscreen ? "0" : "-24px", 
          height: isFullscreen ? "100%" : "calc(100% + 48px)",
          flex: 1, 
          display: "flex", 
          flexDirection: "column",
          overflow: "hidden" 
        }}>
          <WorkPage onBack={handleBackToList} jobInfo={selectedJob} />
        </div>
      </App>
    );
  }

  const columns = [
    { 
      title: t("columns.view", { ns: "project" }), 
      key: "workAction", align: "center" as const, width: 100, 
      render: (_: any, record: LabelingJobRecord) => ( 
        <Button size="small" block icon={<DesktopOutlined />} style={{ background: token.colorFillSecondary, fontSize: 12 }} onClick={() => handleEnterWork(record)}> 
          {t("columns.view", { ns: "project" })} 
        </Button> 
      ) 
    },
    { title: t("modal.prjNm", { ns: "project" }), dataIndex: "prjNm", width: '25%' },
    { title: t("modal.taskNm", { ns: "project" }), dataIndex: "taskNm", width: '10%', align: "center" as const },
    { title: t("columns.jobName", { ns: "project" }), dataIndex: "jobNm", width: '10%', align: "center" as const },
    { 
      title: t("columns.workCount", { ns: "project" }), 
      dataIndex: "workCnt", align: "right" as const, width: 80, 
      render: (v: number) => `${v}${t("unitCases", { ns: "common" })}` 
    },
    { 
      title: t("modal.goal", { ns: "project" }), 
      dataIndex: "goalCnt", align: "right" as const, width: 80, 
      render: (v: number) => `${v}${t("unitCases", { ns: "common" })}` 
    },
    { title: t("listPage.status"), dataIndex: "progress", width: '15%', render: (v: number) => (
      <div style={{ position: "relative", height: 18, display: "flex", alignItems: "center" }}>
        <Progress 
          percent={v} 
          showInfo={false} 
          strokeColor={v === 100 ? "#F87171" : token.colorPrimary} 
          size={18}
          railColor="rgba(255,255,255,0.05)"
          style={{ width: '100%', marginBottom: 0 }} 
        />
        <Text style={{ 
          position: "absolute", left: '50%', transform: "translateX(-50%)", 
          fontSize: 10, color: "#fff", fontWeight: "900", textShadow: "0 1px 2px rgba(0,0,0,0.5)" 
        }}>
          {v}%
        </Text>
      </div>
    ) },
    { title: t("columns.pmNm", { ns: "project" }), dataIndex: "pmNm", align: "center" as const, width: 100 },
    { title: t("columns.start", { ns: "project" }), dataIndex: "startDt", align: "center" as const, width: 100 },
    { title: t("columns.end", { ns: "project" }), dataIndex: "expireDt", align: "center" as const, width: 100 },
  ];

  return (
    <App>
      <div style={{ padding: "0 24px 24px 24px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 20 }}>
          <Title level={4} style={{ margin: 0 }}>{t('listPage.title')}</Title>
          <Breadcrumb 
            items={[
              { title: <Space><HomeOutlined /> {t("listPage.home")}</Space> },
              { title: t("listPage.title") }
            ]} 
          />
        </div>
        <Card title={<Space><InfoCircleOutlined /> <Text strong>{t('listPage.work')}</Text></Space>} variant="borderless" style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary }} styles={{ body: { padding: 0 } }}>
          <Table dataSource={mockJobList} columns={columns as any} size="small" pagination={false} bordered rowClassName={(_, index) => index % 2 === 0 ? "even-row" : "odd-row"} locale={{ emptyText: t("noObjects", { ns: "common" }) }} />
        </Card>
        <style>{` .ant-table-thead > tr > th { background-color: ${token.colorFillQuaternary} !important; font-weight: 600 !important; font-size: 11px !important; color: rgba(255, 255, 255, 0.85) !important; } .ant-table-cell { font-size: 11px !important; } `}</style>
      </div>
    </App>
  );
}
