import React, { useState, useEffect, useRef } from "react";
import { theme, Typography, Space, Button, Divider, App, Modal, Row, Col, ConfigProvider, Tag, Tooltip } from "antd";
import { useTranslation } from "react-i18next";
import {
  CloseOutlined
} from "@ant-design/icons";
import LabelingToolbar from "../../components/LabelingToolbar";
import LabelingStage from "../../components/LabelingStage";
import LabelingObjectList from "../../components/LabelingObjectList";
import LabelingImagePanel from "../../components/LabelingImagePanel";
import { useLabelingStore } from "../../store/useLabelingStore";

const { useToken } = theme;
const { Title, Text } = Typography;
import { useLayout } from "@/framework/layouts/LayoutProvider";
import { i18n } from "@/framework/i18n";
import { loadNamespace } from "@/framework/i18n/loader";

const mockImages = Array.from({ length: 24 }).map((_, i) =>
  `https://picsum.photos/seed/${i + 100}/1600/900`
);

export default function LabelingWorkPage({ onBack, jobInfo }: { onBack: () => void; jobInfo?: any }) {
  const { token } = useToken();
  const { t } = useTranslation(["labeling", "common"]);
  const { message, modal } = App.useApp();
  const {
    currentImageIndex, shapes, setTool, currentTool,
    undo, redo, removeShape, selectedShapeIds, selectShape,
    setCurrentImageIndex, save, toggleLabels, toggleLabelNames,
    resetZoom, zoomIn, zoomOut, pastePreviousShapes, bringForward, sendBackward,
    isFullscreen, toggleFullscreen, toggleLockAll
  } = useLabelingStore();

  const { setIsLayoutHidden } = useLayout();
  const containerRef = useRef<HTMLDivElement>(null);
  const [isHelpOpen, setIsHelpOpen] = useState(false);
  const [isI18nReady, setIsI18nReady] = useState(false);
  const [isPreviewOpen, setIsPreviewOpen] = useState(false);
  const [previewData, setPreviewData] = useState("");

  useEffect(() => {
    setIsLayoutHidden(isFullscreen);
    return () => setIsLayoutHidden(false);
  }, [isFullscreen, setIsLayoutHidden]);
  
  // Ensure 'labeling' namespace is loaded
  useEffect(() => {
    const lng = i18n.language;
    loadNamespace(lng, "platform", "labeling") // Load all labeling resources into 'platform' and 'labeling' ns
      .finally(() => {
        setIsI18nReady(true);
      });
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (document.activeElement?.tagName === "TEXTAREA" || document.activeElement?.tagName === "INPUT") return;

      const isCtrl = e.ctrlKey || e.metaKey;
      const isShift = e.shiftKey;
      const isAlt = e.altKey;

      if (e.key === "Escape") { selectShape(null); setTool("select"); }
      else if (e.key === "b" || e.key === "B") setTool("rect");
      else if (e.key === "p" || e.key === "P") setTool("polygon");
      else if (e.key === "k" || e.key === "K") { if (isAlt) setTool("composite"); else setTool("keypoint"); }
      else if (e.key === "s" || e.key === "S") { if (!isShift) setTool("skeleton"); }

      if (e.key === "PageDown") setCurrentImageIndex(currentImageIndex + 1);
      if (e.key === "PageUp") setCurrentImageIndex(Math.max(0, currentImageIndex - 1));

      if (isCtrl && (e.key === "g" || e.key === "G")) { e.preventDefault(); setTool("group"); }
      if (isCtrl && (e.key === "x" || e.key === "X")) { e.preventDefault(); setTool("scissor"); }
      if (isCtrl && (e.key === "z" || e.key === "Z")) { e.preventDefault(); undo(); }
      if (isCtrl && (e.key === "y" || e.key === "Y")) { e.preventDefault(); redo(); }
      if (isCtrl && e.key === "Delete") { e.preventDefault(); useLabelingStore.getState().removeAllShapes(); }
      if (isCtrl && (e.key === "b" || e.key === "B")) { e.preventDefault(); pastePreviousShapes(); message.success(t("page.pastedPrev")); }
      if (isShift && (e.key === "s" || e.key === "S")) { e.preventDefault(); save(); message.success(t("page.saved")); }
      
      if (e.key === "h" || e.key === "H") toggleLabels();
      if (e.key === "f" && e.ctrlKey) { e.preventDefault(); toggleFullscreen(); }
      else if (e.key === "f" || e.key === "F") toggleLabelNames();
      if (isShift && (e.key === "c" || e.key === "C")) handleComplete();
      if (e.key === "l" || e.key === "L") toggleLockAll();
      if (e.key === "+" || e.key === "=") { e.preventDefault(); zoomIn(); }
      if (e.key === "-") { e.preventDefault(); zoomOut(); }
      if (e.key === "0") resetZoom();
      if (e.key === "ArrowLeft") setCurrentImageIndex(Math.max(0, currentImageIndex - 1));
      if (e.key === "ArrowRight") setCurrentImageIndex(Math.min(mockImages.length - 1, currentImageIndex + 1));

      if (e.key === "q" || e.key === "Q") onBack();
      if (e.key === "`") setIsHelpOpen(prev => !prev);
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [currentImageIndex, undo, redo, save, toggleLabels, toggleLabelNames, setTool, selectShape, onBack, pastePreviousShapes, t, message, toggleFullscreen, toggleLockAll, zoomIn, zoomOut, resetZoom, setCurrentImageIndex]);

  if (!isI18nReady) return null;

  const handleShowPreview = () => {
    const { shapes, imageWidth, imageHeight, classes, imageDescription } = useLabelingStore.getState();
    const format = (jobInfo?.format || "YOLO").toUpperCase();
    const w = imageWidth || 1600; const h = imageHeight || 900;
    
    // 포맷별 좌표 정밀도 도우미
    const fmtNum = (val: number, decimals: number = 0) => {
      if (decimals === 0) return Math.round(val);
      return parseFloat(val.toFixed(decimals));
    };

    let content = "";
    if (format === "YOLO") {
      content = shapes.map(s => {
        if (!s.classId || s.x === undefined || s.y === undefined || s.width === undefined || s.height === undefined) return null;
        const cx = (s.x + s.width / 2) / w;
        const cy = (s.y + s.height / 2) / h;
        const nw = s.width / w;
        const nh = s.height / h;
        // YOLO는 6자리 정밀도 유지
        return `${s.classId} ${cx.toFixed(6)} ${cy.toFixed(6)} ${nw.toFixed(6)} ${nh.toFixed(6)}`;
      }).filter(Boolean).join("\n");
    } else if (format === "COCO") {
      const coco = {
        images: [{ id: 1, file_name: "current_image.jpg", width: w, height: h }],
        annotations: shapes.map((s, i) => ({
          id: i + 1,
          image_id: 1,
          category_id: parseInt(s.classId || "0"),
          // COCO는 픽셀 단위, 소수점 2자리 권장
          bbox: [fmtNum(s.x || 0, 2), fmtNum(s.y || 0, 2), fmtNum(s.width || 0, 2), fmtNum(s.height || 0, 2)],
          area: fmtNum((s.width || 0) * (s.height || 0), 2),
          segmentation: s.points ? [s.points.map(p => fmtNum(p, 2))] : [],
          iscrowd: 0
        })),
        categories: classes.map(c => ({ id: parseInt(c.id), name: c.name }))
      };
      content = JSON.stringify(coco, null, 2);
    } else if (format === "NIA") {
      const nia = {
        raw_data_info: { 
          image_id: "IMG_0001", resolution: [w, h], date: new Date().toISOString(),
          description: imageDescription || ""
        },
        learning_data_info: {
          annotations: shapes.map(s => {
            const base = { class_nm: s.className, type: s.type, attributes: s.attributes || {} };
            // NIA는 가시성을 고려하여 보통 정수 좌표 사용
            if (s.type === "rect") {
              return { ...base, coordinates: [Math.round(s.x || 0), Math.round(s.y || 0), Math.round(s.width || 0), Math.round(s.height || 0)] };
            } 
            if (s.type === "polygon" && s.points) {
              const pairs = [];
              for (let i = 0; i < s.points.length; i += 2) {
                pairs.push([Math.round(s.points[i]), Math.round(s.points[i+1])]);
              }
              return { ...base, points: pairs };
            }
            if (s.type === "keypoint" && s.keypointParts) {
              return { 
                ...base, 
                keypoints: s.keypointParts.map(p => ({
                  name: p.name,
                  x: Math.round((s.x || 0) + p.x),
                  y: Math.round((s.y || 0) + p.y),
                  visibility: p.visibility
                }))
              };
            }
            return { ...base, coordinates: [Math.round(s.x || 0), Math.round(s.y || 0), Math.round(s.width || 0), Math.round(s.height || 0)] };
          })
        }
      };
      content = JSON.stringify(nia, null, 2);
    } else {
      content = JSON.stringify(shapes, null, 2);
    }

    if (!content || (format === "YOLO" && content.includes("No valid"))) {
      content = `No valid labels found for ${format} format.`;
    }
    
    setPreviewData(content);
    setIsPreviewOpen(true);
  };

  const handleComplete = () => {
    modal.confirm({
      title: t('work.complete'),
      content: t('page.saveComplete'),
      okText: t('confirm', { ns: "common" }),
      cancelText: t('cancel', { ns: "common" }),
      onOk: () => {
        save();
        message.success(t('page.saved'));
        onBack();
      }
    });
  };

  return (
    <div
      ref={containerRef}
      className="labeling-work-container"
      style={{
        height: "100%", width: "100%", flex: 1, display: "flex", flexDirection: "column",
        background: token.colorBgLayout, overflow: "hidden", color: token.colorText, position: "relative"
      }}
    >
      <ConfigProvider getPopupContainer={() => containerRef.current || document.body}>
        <div style={{ height: "40px", padding: "0 12px", background: token.colorBgElevated, borderBottom: `1px solid ${token.colorBorderSecondary}`, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <Space size={16}>
            <Text style={{ fontSize: 13, color: token.colorText, fontWeight: "bold" }}>
              [{jobInfo?.prjNm || t('page.defaultProject')}] - {jobInfo?.jobNm || t('page.defaultJob')}
            </Text>
            <Tooltip title={t('page.clickToPreview')}>
              <Tag 
                color={jobInfo?.format ? "processing" : "default"} 
                variant="filled"
                style={{ 
                  margin: 0, borderRadius: 10, fontSize: 10, fontWeight: "bold", 
                  cursor: "pointer", transition: "all 0.2s" 
                }}
                onClick={handleShowPreview}
              >
                {(jobInfo?.format || "YOLO").toUpperCase()}
              </Tag>
            </Tooltip>
          </Space>

          <div style={{
            background: token.colorFillAlter, padding: "4px 16px", borderRadius: 20, display: "flex", alignItems: "center",
            gap: 10, border: `1px solid ${token.colorBorderSecondary}`, boxShadow: "inset 0 1px 2px rgba(0,0,0,0.1)"
          }}>
            <div style={{ width: 8, height: 8, borderRadius: "50%", background: token.colorSuccess }} />
            <Text style={{ fontSize: 11, color: token.colorTextSecondary }}>
              {currentTool === "rect" ? t("page.startBbox") :
                currentTool === "polygon" ? t("page.startPolygon") :
                  currentTool === "select" ? t("page.selectMode") :
                    `${currentTool} ${t("page.drawing")}`}
            </Text>
          </div>

          <Space size={12}>
            <Button size="small" type="primary" style={{ height: 26, fontSize: 11, fontWeight: "bold" }} onClick={handleComplete}>
              {t('page.completeAction')} (Shift+C)
            </Button>
            <Divider orientation="vertical" style={{ height: 16, margin: 0, borderColor: token.colorBorderSecondary }} />
            <Button type="text" size="small" icon={<CloseOutlined style={{ fontSize: 14, color: token.colorTextDescription }} />} onClick={onBack} />
          </Space>
        </div>

        <div style={{ flex: 1, display: "flex", position: "relative", overflow: "hidden" }}>
          <div style={{ width: "48px", flexShrink: 0, background: token.colorBgContainer, borderRight: `1px solid ${token.colorBorderSecondary}` }}>
            <LabelingToolbar onShowHelp={() => setIsHelpOpen(true)} onExit={onBack} />
          </div>
          <div style={{ flex: 1, minWidth: 0, position: "relative", background: token.colorBgBase }}>
            <LabelingStage imageUrl={mockImages[currentImageIndex] || mockImages[0]} onShowHelp={() => setIsHelpOpen(prev => !prev)} />
          </div>
          <div style={{ 
            width: "320px", 
            minWidth: "320px",
            flexShrink: 0,
            background: token.colorBgElevated, 
            borderLeft: `1px solid ${token.colorBorderSecondary}`, 
            display: "flex", 
            flexDirection: "column" 
          }}>
            <LabelingObjectList />
          </div>
        </div>
        <div style={{ width: "100%", background: token.colorBgContainer, borderTop: `1px solid ${token.colorBorderSecondary}` }}>
          <LabelingImagePanel />
        </div>
      </ConfigProvider>

      <Modal
        title={<Title level={5} style={{ margin: 0 }}>📄 {t('page.exportPreview')} ({(jobInfo?.format || "YOLO").toUpperCase()})</Title>}
        open={isPreviewOpen}
        onCancel={() => setIsPreviewOpen(false)}
        footer={[
          <Button key="close" onClick={() => setIsPreviewOpen(false)}>
            {t('common:close')}
          </Button>
        ]}
        width={600}
        centered
      >
        <div style={{ 
          background: token.colorFillTertiary, padding: 16, borderRadius: 8, 
          maxHeight: 400, overflowY: 'auto', border: `1px solid ${token.colorBorder}` 
        }}>
          <pre style={{ margin: 0, fontSize: 12, color: token.colorText, whiteSpace: 'pre-wrap', fontFamily: 'monospace' }}>
            {previewData}
          </pre>
        </div>
      </Modal>

      <Modal
        title={<Title level={5} style={{ color: token.colorText, margin: 0 }}>⌨️ {t('toolbar.help').replace(' (`)', '')}</Title>}
        open={isHelpOpen}
        onCancel={() => setIsHelpOpen(false)}
        footer={null}
        width={800}
        centered
        styles={{ body: { background: token.colorBgElevated, padding: "24px" } }}
      >
        <Row gutter={[48, 24]}>
          <Col span={12}>
            <Text strong style={{ color: token.colorPrimary, display: "block", marginBottom: 12, fontSize: 13 }}>{t('page.generalShortcuts')}</Text>
            <HelpRow keys="`" desc={t('page.closeHelp')} />
            <HelpRow keys="PgUp PgDn" desc={t('page.prevNextImage')} />
            <HelpRow keys="H F L" desc={t('page.displayModes')} />
            <HelpRow keys="+ - R" desc={t('page.zoomModes')} />
            <HelpRow keys="[ ]" desc={t('page.layerModes')} />
            <HelpRow keys="Shift + S" desc={t('page.saveComplete')} />
            <HelpRow keys="Shift + D" desc={t('page.defectToggle')} />
            <HelpRow keys="Shift + W" desc={t('page.workToggle')} />
            <HelpRow keys="Q" desc={t('page.exitWork')} />
          </Col>
          <Col span={12}>
            <Text strong style={{ color: token.colorPrimary, display: "block", marginBottom: 12, fontSize: 13 }}>{t('page.editShortcuts')}</Text>
            <HelpRow keys="Esc" desc={t('page.selectTool')} />
            <HelpRow keys="B P K S" desc={t('page.drawTools')} />
            <HelpRow keys="Alt + K" desc={t('page.compositeTool')} />
            <HelpRow keys="Ctrl + X" desc={t('page.scissorTool')} />
            <HelpRow keys="Ctrl + G" desc={t('page.groupTool')} />
            <HelpRow keys="Ctrl + C V" desc={t('page.copyPaste')} />
            <HelpRow keys="Ctrl + B" desc={t('page.pastePrev')} />
            <HelpRow keys="Ctrl + Z Y" desc={t('page.undoRedo')} />
            <HelpRow keys="Delete" desc={t('page.deleteTool')} />
            <HelpRow keys="Ctrl + Delete" desc={t('page.deleteAllTool')} />
            <HelpRow keys="0 ~ 9" desc={t('page.classSelect')} />
          </Col>
        </Row>
      </Modal>
    </div>
  );
}

function HelpRow({ keys, desc }: { keys: string; desc: string }) {
  const { token } = useToken();
  return (
    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
      <Space size={4} wrap>
        {keys.split(" ").map((k, i) => (
          <div key={i} style={{ background: token.colorFillSecondary, padding: "2px 8px", borderRadius: 4, border: `1px solid ${token.colorBorderSecondary}`, color: token.colorText, fontSize: 10, minWidth: 28, textAlign: "center", boxShadow: `0 2px 0 ${token.colorFillQuaternary}` }}>{k}</div>
        ))}
      </Space>
      <Text style={{ color: token.colorTextSecondary, fontSize: 11 }}>{desc}</Text>
    </div>
  )
}
